window.PROJECT_FILES = {"app.py":"import os\nimport sys\nimport asyncio\nimport threading\nimport queue\nimport logging\nimport requests\n\n# 確保本檔所在目錄在 import 路徑上 (環境可能啟用 PYTHONSAFEPATH)\nsys.path.insert(0, os.path.dirname(os.path.abspath(__file__)))\n\nfrom flask import Flask, render_template, request, jsonify, send_from_directory\nfrom flask_socketio import SocketIO, emit\nfrom dotenv import load_dotenv\nfrom google import genai\n\nimport providers\n\n# Load Env with override\nload_dotenv(override=True)\n# 有效金鑰解析：優先環境變數 GEMINI_API_KEY，其次 .env 的 GOOGLE_API_KEY\nAPI_KEY = os.getenv(\"GEMINI_API_KEY\") or os.getenv(\"GOOGLE_API_KEY\")\nif API_KEY:\n    print(f\"🔑 API Key loaded (starts with): {API_KEY[:6]}...\")\nelse:\n    print(\"❌ API Key NOT found! (set GEMINI_API_KEY or GOOGLE_API_KEY)\")\n\n# App Setup\napp = Flask(__name__)\napp.config['SECRET_KEY'] = 'gemini_secret!'\nsocketio = SocketIO(app, cors_allowed_origins=\"*\", async_mode='threading')\n\n# Logging\nlogging.basicConfig(level=logging.INFO)\nlogger = logging.getLogger(__name__)\n\n# Gemini Live realtime 模型 (即時語音對話模式)\n# gemini-3.5-live-translate-preview：3.5、專為即時翻譯設計，原生語音 AUDIO 輸出\n# （若即時翻譯品質或行為異常，可回退 gemini-3.1-flash-live-preview）\nLIVE_MODEL = \"gemini-3.5-live-translate-preview\"\n\n# Session Storage: Key: sid, Value: GeminiSession\nactive_sessions = {}\n\n\nclass GeminiSession:\n    \"\"\"Gemini Live 即時語音串流 (招牌『即時模式』)。\"\"\"\n\n    def __init__(self, sid, instructions, api_key=None):\n        self.sid = sid\n        self.instructions = instructions\n        self.audio_in_queue = queue.Queue()\n        self.stop_event = threading.Event()\n        self.thread = None\n        self.client = genai.Client(api_key=(api_key or API_KEY), http_options={'api_version': 'v1alpha'})\n\n    def start(self):\n        self.thread = threading.Thread(target=self.run_loop)\n        self.thread.start()\n\n    def stop(self):\n        self.stop_event.set()\n        if self.thread:\n            self.thread.join(timeout=2)\n\n    def add_audio(self, audio_data):\n        self.audio_in_queue.put(audio_data)\n\n    def run_loop(self):\n        asyncio.run(self.async_process())\n\n    async def async_process(self):\n        config = {\n            \"response_modalities\": [\"AUDIO\"],           # 原生語音模型只支援 AUDIO\n            \"system_instruction\": self.instructions,\n            \"output_audio_transcription\": {},            # 同時取得字幕文字\n        }\n        try:\n            async with self.client.aio.live.connect(model=LIVE_MODEL, config=config) as session:\n                logger.info(f\"Session {self.sid} connected to Gemini Live.\")\n                sender_task = asyncio.create_task(self.sender(session))\n                receiver_task = asyncio.create_task(self.receiver(session))\n\n                while not self.stop_event.is_set():\n                    if receiver_task.done():\n                        receiver_task = asyncio.create_task(self.receiver(session))\n                    if sender_task.done() and not sender_task.cancelled():\n                        exc = sender_task.exception() if not sender_task.cancelled() else None\n                        if exc:\n                            logger.error(f\"Sender task died: {exc}\")\n                            sender_task = asyncio.create_task(self.sender(session))\n                    await asyncio.sleep(0.1)\n\n                sender_task.cancel()\n                receiver_task.cancel()\n        except Exception as e:\n            logger.error(f\"Gemini connection error: {e}\")\n            socketio.emit('error', {'msg': str(e)}, to=self.sid)\n\n    async def sender(self, session):\n        while True:\n            try:\n                if not self.audio_in_queue.empty():\n                    chunk = self.audio_in_queue.get()\n                    from google.genai.types import Blob\n                    audio_blob = Blob(data=chunk, mime_type=\"audio/pcm\")\n                    await session.send_realtime_input(audio=audio_blob)\n                else:\n                    await asyncio.sleep(0.01)\n            except asyncio.CancelledError:\n                break\n            except Exception as e:\n                logger.error(f\"Sender Error: {e}\")\n                await asyncio.sleep(0.1)\n\n    async def receiver(self, session):\n        try:\n            async for response in session.receive():\n                if self.stop_event.is_set():\n                    break\n                server_content = response.server_content\n                if server_content is not None:\n                    # 字幕（原生語音的逐字轉錄）\n                    ot = getattr(server_content, 'output_transcription', None)\n                    if ot is not None and getattr(ot, 'text', None):\n                        socketio.emit('text_response', {'text': ot.text}, to=self.sid)\n                    model_turn = server_content.model_turn\n                    if model_turn is not None:\n                        for part in model_turn.parts:\n                            inline = getattr(part, 'inline_data', None)\n                            if inline is not None and inline.data:\n                                socketio.emit('audio_response', inline.data, to=self.sid)   # 24kHz PCM 語音\n                            elif getattr(part, 'text', None):\n                                socketio.emit('text_response', {'text': part.text}, to=self.sid)\n                    if server_content.turn_complete:\n                        socketio.emit('turn_complete', to=self.sid)\n        except asyncio.CancelledError:\n            pass\n        except Exception as e:\n            logger.error(f\"Receiver Error: {e}\")\n            socketio.emit('error', {'msg': str(e)}, to=self.sid)\n\n\n# --- Flask Routes ---\n@app.route('/')\ndef index():\n    return render_template('index.html')\n\n\n@app.route('/api/health')\ndef health():\n    return jsonify({\n        \"ok\": True,\n        \"gemini_key\": bool(API_KEY),\n        \"live_model\": LIVE_MODEL,\n    })\n\n\n@app.route('/api/translate', methods=['POST'])\ndef api_translate():\n    \"\"\"通用翻譯端點：支援 OpenAI 相容 / Gemini。前端傳供應商設定，後端代理。\"\"\"\n    data = request.get_json(force=True, silent=True) or {}\n    result = providers.translate(data)\n    status = 200 if result.get(\"ok\") else 400\n    return jsonify(result), status\n\n\n# 上傳檔案翻譯：支援 圖片 / PDF / 純文字檔\nMAX_FILE_BYTES = 15 * 1024 * 1024   # 15MB\nIMAGE_EXTS = {'jpg', 'jpeg', 'png', 'webp', 'heic', 'heif', 'gif'}\n\n\ndef _provider_cfg(src):\n    \"\"\"從 request (json 或 form) 取出供應商設定。\"\"\"\n    provider = (src.get('provider') or 'gemini').lower()\n    return {\n        'provider': provider,\n        'base_url': src.get('base_url') or '',\n        'api_key': src.get('api_key') or '',\n        'model': src.get('model') or '',\n    }\n\n\ndef _run_analyze(pc, target, force_gemini=False, **kw):\n    \"\"\"\n    依供應商設定執行 providers.analyze，統一處理金鑰解析與錯誤。\n    force_gemini=True 時（例如 PDF）強制走伺服器 Gemini 金鑰。\n    回傳 (result_dict, status_code)。\n    \"\"\"\n    provider = pc['provider']\n    note = None\n    if force_gemini and provider != 'gemini':\n        provider = 'gemini'\n        note = 'PDF 不支援所選供應商，已自動改用 Gemini 雲端辨識'\n\n    try:\n        if provider == 'openai':\n            if not pc['api_key']:\n                return {\"ok\": False, \"error\": \"OpenAI 相容供應商需要 API Key（請到設定填入）\"}, 400\n            result = providers.analyze('openai', pc['api_key'], pc['model'], target,\n                                       base_url=pc['base_url'], **kw)\n        else:  # gemini\n            key = (pc['api_key'] if pc['provider'] == 'gemini' else '') or API_KEY\n            if not key:\n                return {\"ok\": False, \"error\": \"找不到 Gemini API Key\"}, 400\n            model = pc['model'] if pc['provider'] == 'gemini' else ''\n            result = providers.analyze('gemini', key, model, target, **kw)\n    except requests.HTTPError as e:\n        body = ''\n        try:\n            body = e.response.text[:300]\n        except Exception:\n            pass\n        return {\"ok\": False, \"error\": f\"HTTP {e.response.status_code if e.response else '?'}: {body}\"}, 400\n    except Exception as e:\n        logger.error(f\"analyze error: {e}\")\n        return {\"ok\": False, \"error\": f\"{type(e).__name__}: {e}\"}, 400\n\n    out = {\"ok\": True, **result}\n    if note:\n        out[\"note\"] = note\n    return out, 200\n\n\n@app.route('/api/vision', methods=['POST'])\ndef api_vision():\n    \"\"\"相機拍照 → 摘要 + 翻譯。前端傳 base64 影像（可含 dataURL 前綴）+ 供應商設定。\"\"\"\n    import base64 as _b64\n    data = request.get_json(force=True, silent=True) or {}\n    image_b64 = data.get('image') or ''\n    target = data.get('target') or 'Traditional Chinese (Taiwan)'\n    if not image_b64:\n        return jsonify({\"ok\": False, \"error\": \"no image\"}), 400\n\n    mime = 'image/jpeg'\n    if image_b64.startswith('data:'):\n        try:\n            header, image_b64 = image_b64.split(',', 1)\n            mime = header.split(':', 1)[1].split(';', 1)[0] or mime\n        except Exception:\n            pass\n    try:\n        raw = _b64.b64decode(image_b64)\n    except Exception:\n        return jsonify({\"ok\": False, \"error\": \"影像解碼失敗\"}), 400\n\n    pc = _provider_cfg(data)\n    result, status = _run_analyze(pc, target, file_bytes=raw, mime_type=mime)\n    return jsonify(result), status\n\n\n@app.route('/api/file', methods=['POST'])\ndef api_file():\n    \"\"\"上傳檔案 → 摘要 + 翻譯。支援 image/* 、application/pdf 、text/plain。PDF 一律走 Gemini。\"\"\"\n    f = request.files.get('file')\n    target = request.form.get('target') or 'Traditional Chinese (Taiwan)'\n    if not f:\n        return jsonify({\"ok\": False, \"error\": \"no file\"}), 400\n\n    filename = f.filename or 'upload'\n    raw = f.read()\n    if not raw:\n        return jsonify({\"ok\": False, \"error\": \"空白檔案\"}), 400\n    if len(raw) > MAX_FILE_BYTES:\n        return jsonify({\"ok\": False, \"error\": \"檔案過大（上限 15MB）\"}), 400\n\n    mime = (f.mimetype or '').lower()\n    ext = filename.rsplit('.', 1)[-1].lower() if '.' in filename else ''\n    pc = _provider_cfg(request.form)\n\n    if mime == 'text/plain' or ext in ('txt', 'md', 'csv'):\n        text = raw.decode('utf-8', errors='replace')\n        result, status = _run_analyze(pc, target, text=text)\n    elif mime == 'application/pdf' or ext == 'pdf':\n        # PDF 只有 Gemini 能原生讀取 → 強制回退 Gemini\n        result, status = _run_analyze(pc, target, force_gemini=True,\n                                      file_bytes=raw, mime_type='application/pdf')\n    elif mime.startswith('image/') or ext in IMAGE_EXTS:\n        if not mime.startswith('image/'):\n            mime = 'image/jpeg'\n        result, status = _run_analyze(pc, target, file_bytes=raw, mime_type=mime)\n    else:\n        return jsonify({\"ok\": False, \"error\": f\"不支援的檔案類型：{mime or ext or '未知'}\"}), 400\n\n    if isinstance(result, dict):\n        result.setdefault(\"filename\", filename)\n    return jsonify(result), status\n\n\n# 天氣：Open-Meteo（免金鑰）。地名→經緯度→即時天氣＋帶傘建議\nWMO_CODES = {\n    0: \"晴天 ☀️\", 1: \"大致晴朗 🌤️\", 2: \"部分多雲 ⛅\", 3: \"陰天 ☁️\",\n    45: \"有霧 🌫️\", 48: \"凍霧 🌫️\",\n    51: \"毛毛雨 🌦️\", 53: \"毛毛雨 🌦️\", 55: \"毛毛雨 🌦️\",\n    56: \"凍雨 🌧️\", 57: \"凍雨 🌧️\",\n    61: \"小雨 🌧️\", 63: \"中雨 🌧️\", 65: \"大雨 🌧️\",\n    66: \"凍雨 🌧️\", 67: \"凍雨 🌧️\",\n    71: \"小雪 🌨️\", 73: \"中雪 🌨️\", 75: \"大雪 🌨️\", 77: \"雪珠 🌨️\",\n    80: \"陣雨 🌦️\", 81: \"陣雨 🌧️\", 82: \"強陣雨 ⛈️\",\n    85: \"陣雪 🌨️\", 86: \"強陣雪 🌨️\",\n    95: \"雷陣雨 ⛈️\", 96: \"雷雨伴冰雹 ⛈️\", 99: \"強雷雨冰雹 ⛈️\",\n}\n\n\n# 常見旅遊地點（中文名 → 座標＋顯示名）：保證熱門地點精準，避免地理編碼誤配\nCOMMON_PLACES = {\n    \"台北\": (25.033, 121.565, \"台北，台灣\"), \"臺北\": (25.033, 121.565, \"台北，台灣\"),\n    \"台中\": (24.147, 120.673, \"台中，台灣\"), \"台南\": (22.999, 120.227, \"台南，台灣\"),\n    \"高雄\": (22.627, 120.301, \"高雄，台灣\"), \"花蓮\": (23.991, 121.601, \"花蓮，台灣\"),\n    \"台東\": (22.758, 121.144, \"台東，台灣\"), \"墾丁\": (21.947, 120.798, \"墾丁，台灣\"),\n    \"東京\": (35.690, 139.692, \"東京，日本\"), \"大阪\": (34.694, 135.502, \"大阪，日本\"),\n    \"京都\": (35.011, 135.768, \"京都，日本\"), \"名古屋\": (35.182, 136.906, \"名古屋，日本\"),\n    \"福岡\": (33.590, 130.402, \"福岡，日本\"), \"札幌\": (43.062, 141.354, \"札幌，日本\"),\n    \"北海道\": (43.062, 141.354, \"北海道，日本\"), \"沖繩\": (26.212, 127.681, \"沖繩，日本\"),\n    \"那霸\": (26.212, 127.681, \"那霸，日本\"), \"首爾\": (37.567, 126.978, \"首爾，韓國\"),\n    \"釜山\": (35.180, 129.075, \"釜山，韓國\"), \"曼谷\": (13.756, 100.502, \"曼谷，泰國\"),\n    \"清邁\": (18.788, 98.985, \"清邁，泰國\"), \"普吉島\": (7.880, 98.392, \"普吉島，泰國\"),\n    \"新加坡\": (1.352, 103.820, \"新加坡\"), \"香港\": (22.320, 114.170, \"香港\"),\n    \"澳門\": (22.199, 113.544, \"澳門\"), \"吉隆坡\": (3.139, 101.687, \"吉隆坡，馬來西亞\"),\n    \"峇里島\": (-8.409, 115.189, \"峇里島，印尼\"), \"峴港\": (16.055, 108.202, \"峴港，越南\"),\n    \"胡志明市\": (10.823, 106.630, \"胡志明市，越南\"), \"河內\": (21.028, 105.834, \"河內，越南\"),\n    \"上海\": (31.230, 121.474, \"上海，中國\"), \"北京\": (39.904, 116.407, \"北京，中國\"),\n}\n\n\ndef _geocode(place):\n    \"\"\"中文地名 → (lat, lon, 顯示名)。內建常見地點 → Nominatim → Open-Meteo。查無回 None。\"\"\"\n    key = place.strip()\n    if key in COMMON_PLACES:\n        lat, lon, name = COMMON_PLACES[key]\n        return lat, lon, name\n    # Nominatim（OpenStreetMap，免金鑰，中文支援佳；須帶 User-Agent）\n    try:\n        r = requests.get(\"https://nominatim.openstreetmap.org/search\",\n                         params={\"q\": place, \"format\": \"json\", \"limit\": 1, \"accept-language\": \"zh-TW\"},\n                         headers={\"User-Agent\": \"liang-translator/1.0 (travel weather)\"}, timeout=10)\n        d = r.json()\n        if d:\n            item = d[0]\n            disp = item.get(\"display_name\", place).split(\",\")\n            name = disp[0].strip() + ((\"，\" + disp[-1].strip()) if len(disp) > 1 else \"\")\n            return float(item[\"lat\"]), float(item[\"lon\"]), name\n    except Exception as e:\n        logger.warning(f\"nominatim failed: {e}\")\n    # Open-Meteo 地理編碼（備援）\n    try:\n        g = requests.get(\"https://geocoding-api.open-meteo.com/v1/search\",\n                         params={\"name\": place, \"count\": 1, \"language\": \"zh\"}, timeout=8).json()\n        results = g.get(\"results\") or []\n        if results:\n            loc = results[0]\n            name = loc.get(\"name\", place) + ((\"，\" + loc[\"country\"]) if loc.get(\"country\") else \"\")\n            return loc[\"latitude\"], loc[\"longitude\"], name\n    except Exception as e:\n        logger.warning(f\"open-meteo geocode failed: {e}\")\n    return None\n\n\ndef _weather_advice(code, temp, pop):\n    tips = []\n    rainy = code in (51, 53, 55, 56, 57, 61, 63, 65, 66, 67, 80, 81, 82, 95, 96, 99) or (pop is not None and pop >= 50)\n    if rainy:\n        tips.append(\"☂️ 建議帶傘\")\n    if temp is not None:\n        if temp >= 30:\n            tips.append(\"🧴 高溫，注意防曬補水\")\n        elif temp <= 12:\n            tips.append(\"🧥 偏冷，記得保暖\")\n    if not tips:\n        tips.append(\"👍 天氣舒適，玩得開心\")\n    return \"，\".join(tips)\n\n\n@app.route('/api/weather', methods=['POST'])\ndef api_weather():\n    data = request.get_json(force=True, silent=True) or {}\n    place = (data.get('place') or '').strip()\n    lat = data.get('lat')\n    lon = data.get('lon')\n    name = place or \"目前位置\"\n    try:\n        # 有地名先地理編碼；否則用前端傳來的經緯度（目前位置）\n        if place:\n            geo = _geocode(place)\n            if not geo:\n                return jsonify({\"ok\": False, \"error\": f\"找不到地點「{place}」\"}), 400\n            lat, lon, name = geo\n        if lat is None or lon is None:\n            return jsonify({\"ok\": False, \"error\": \"缺少地點或座標\"}), 400\n\n        # 選填：若有 OpenWeatherMap 金鑰就改用 OWM（否則走免金鑰 Open-Meteo）\n        owm_key = (data.get('owm_key') or '').strip()\n        if owm_key:\n            o = requests.get(\"https://api.openweathermap.org/data/2.5/weather\", params={\n                \"lat\": lat, \"lon\": lon, \"appid\": owm_key, \"units\": \"metric\", \"lang\": \"zh_tw\",\n            }, timeout=8).json()\n            if str(o.get(\"cod\")) == \"200\":\n                main = o.get(\"main\") or {}\n                wid = ((o.get(\"weather\") or [{}])[0]).get(\"id\", 800)\n                desc = ((o.get(\"weather\") or [{}])[0]).get(\"description\", \"—\")\n                raining = wid < 700\n                temp = main.get(\"temp\")\n                return jsonify({\n                    \"ok\": True, \"place\": name, \"temp\": temp,\n                    \"feels\": main.get(\"feels_like\"), \"humidity\": main.get(\"humidity\"),\n                    \"desc\": desc, \"pop\": None,\n                    \"hi\": main.get(\"temp_max\"), \"lo\": main.get(\"temp_min\"),\n                    \"advice\": _weather_advice(61 if raining else 0, temp, None),\n                    \"source\": \"owm\",\n                })\n            # OWM 失敗就繼續走 Open-Meteo\n\n        w = requests.get(\"https://api.open-meteo.com/v1/forecast\", params={\n            \"latitude\": lat, \"longitude\": lon,\n            \"current\": \"temperature_2m,relative_humidity_2m,apparent_temperature,weather_code,precipitation\",\n            \"daily\": \"temperature_2m_max,temperature_2m_min,precipitation_probability_max\",\n            \"timezone\": \"auto\", \"forecast_days\": 1,\n        }, timeout=8).json()\n        cur = w.get(\"current\") or {}\n        daily = w.get(\"daily\") or {}\n        code = cur.get(\"weather_code\")\n        temp = cur.get(\"temperature_2m\")\n        pop = (daily.get(\"precipitation_probability_max\") or [None])[0]\n        hi = (daily.get(\"temperature_2m_max\") or [None])[0]\n        lo = (daily.get(\"temperature_2m_min\") or [None])[0]\n        return jsonify({\n            \"ok\": True, \"place\": name,\n            \"temp\": temp, \"feels\": cur.get(\"apparent_temperature\"),\n            \"humidity\": cur.get(\"relative_humidity_2m\"),\n            \"desc\": WMO_CODES.get(code, \"—\"),\n            \"pop\": pop, \"hi\": hi, \"lo\": lo,\n            \"advice\": _weather_advice(code, temp, pop),\n        })\n    except Exception as e:\n        logger.error(f\"weather error: {e}\")\n        return jsonify({\"ok\": False, \"error\": f\"天氣查詢失敗：{type(e).__name__}\"}), 400\n\n\n# 匯率換算：免金鑰。主用 open.er-api.com（含 TWD 等多幣別），備援 frankfurter.app（歐洲央行）\n@app.route('/api/currency', methods=['POST'])\ndef api_currency():\n    data = request.get_json(force=True, silent=True) or {}\n    base = (data.get('base') or 'USD').upper()\n    target = (data.get('target') or 'TWD').upper()\n    try:\n        amount = float(data.get('amount', 1) or 1)\n    except (TypeError, ValueError):\n        amount = 1.0\n\n    if base == target:\n        return jsonify({\"ok\": True, \"base\": base, \"target\": target, \"amount\": amount,\n                        \"rate\": 1.0, \"result\": amount, \"date\": \"\", \"source\": \"same\"})\n\n    # 主：open.er-api.com（免金鑰，幣別多，含 TWD）\n    try:\n        r = requests.get(f\"https://open.er-api.com/v6/latest/{base}\", timeout=8)\n        r.raise_for_status()\n        d = r.json()\n        rate = (d.get(\"rates\") or {}).get(target)\n        if rate:\n            return jsonify({\"ok\": True, \"base\": base, \"target\": target, \"amount\": amount,\n                            \"rate\": rate, \"result\": amount * rate,\n                            \"date\": d.get(\"time_last_update_utc\", \"\"), \"source\": \"er-api\"})\n    except Exception as e:\n        logger.warning(f\"currency er-api failed: {e}\")\n\n    # 備援：frankfurter.app（歐洲央行，無 TWD 等部分亞幣）\n    try:\n        r = requests.get(\"https://api.frankfurter.app/latest\",\n                         params={\"from\": base, \"to\": target}, timeout=8)\n        r.raise_for_status()\n        d = r.json()\n        rate = (d.get(\"rates\") or {}).get(target)\n        if rate:\n            return jsonify({\"ok\": True, \"base\": base, \"target\": target, \"amount\": amount,\n                            \"rate\": rate, \"result\": amount * rate,\n                            \"date\": d.get(\"date\", \"\"), \"source\": \"frankfurter\"})\n    except Exception as e:\n        logger.warning(f\"currency frankfurter failed: {e}\")\n\n    return jsonify({\"ok\": False, \"error\": f\"查不到 {base}→{target} 匯率（請確認幣別代碼）\"}), 400\n\n\n# 旅遊問答／助手：可選 Tavily 上網 + 走設定供應商的 LLM 回答\ndef _tavily_search(key, query, max_results=5):\n    r = requests.post(\"https://api.tavily.com/search\", json={\n        \"api_key\": key, \"query\": query, \"max_results\": max_results,\n        \"include_answer\": True, \"search_depth\": \"basic\",\n    }, timeout=20)\n    r.raise_for_status()\n    return r.json()\n\n\n@app.route('/api/ask', methods=['POST'])\ndef api_ask():\n    data = request.get_json(force=True, silent=True) or {}\n    question = (data.get('question') or '').strip()\n    if not question:\n        return jsonify({\"ok\": False, \"error\": \"請輸入問題\"}), 400\n    target = data.get('target') or 'Traditional Chinese (Taiwan)'\n    pc = _provider_cfg(data)\n    tavily_key = (data.get('tavily_key') or os.getenv('TAVILY_API_KEY') or '').strip()\n\n    # 1) 有 Tavily 金鑰才上網查；失敗或額度爆掉就略過，改用 AI 自身知識\n    context, sources, searched, search_note = \"\", [], False, \"\"\n    if tavily_key:\n        try:\n            d = _tavily_search(tavily_key, question)\n            results = d.get(\"results\") or []\n            if d.get(\"answer\"):\n                context += f\"Web summary: {d['answer']}\\n\"\n            for it in results:\n                context += f\"- {it.get('title','')}: {it.get('content','')}\\n\"\n                sources.append({\"title\": it.get(\"title\", \"\"), \"url\": it.get(\"url\", \"\")})\n            searched = bool(results or d.get(\"answer\"))\n        except Exception as e:\n            logger.warning(f\"tavily failed: {e}\")\n            search_note = \"（即時搜尋暫時無法使用，改用 AI 既有知識回答）\"\n\n    # 2) 交給 LLM 回答（走設定的供應商）\n    system = (\n        \"You are a helpful, concise travel assistant. \"\n        f\"Answer the user's question in {target}. \"\n        \"If web search context is provided, prefer those up-to-date facts and be specific; \"\n        \"otherwise answer from your own knowledge and flag uncertainty for time-sensitive details. \"\n        \"Use short paragraphs or bullet points when helpful.\"\n    )\n    user = question if not context else f\"Question: {question}\\n\\nWeb search context:\\n{context}\"\n    try:\n        if pc['provider'] == 'openai':\n            if not pc['api_key']:\n                return jsonify({\"ok\": False, \"error\": \"OpenAI 相容供應商需要 API Key（請到設定填入）\"}), 400\n            answer = providers.generate('openai', pc['api_key'], pc['model'], pc['base_url'], system, user)\n        else:\n            key = pc['api_key'] or API_KEY\n            if not key:\n                return jsonify({\"ok\": False, \"error\": \"找不到 Gemini API Key\"}), 400\n            answer = providers.generate('gemini', key, pc['model'], '', system, user)\n    except requests.HTTPError as e:\n        body = ''\n        try:\n            body = e.response.text[:300]\n        except Exception:\n            pass\n        return jsonify({\"ok\": False, \"error\": f\"HTTP {e.response.status_code if e.response else '?'}: {body}\"}), 400\n    except Exception as e:\n        logger.error(f\"ask error: {e}\")\n        return jsonify({\"ok\": False, \"error\": f\"{type(e).__name__}: {e}\"}), 400\n\n    return jsonify({\"ok\": True, \"answer\": (answer or \"\") + ((\"\\n\\n\" + search_note) if search_note else \"\"),\n                    \"sources\": sources, \"searched\": searched})\n\n\n# 雲端 TTS：用 Gemini 原生語音朗讀「任何語言」，不依賴手機內建語音包\n# 用帳號可用的最新 TTS 模型（2.5 preview 已偏舊，改用 3.1）\nTTS_MODEL = \"gemini-3.1-flash-tts-preview\"\n\n\n@app.route('/api/tts', methods=['POST'])\ndef api_tts():\n    from flask import Response\n    data = request.get_json(force=True, silent=True) or {}\n    text = (data.get('text') or '').strip()\n    if not text:\n        return ('', 204)\n    key = (data.get('gemini_key') or '').strip() or API_KEY   # 選填覆蓋，留空用伺服器內建\n    if not key:\n        return jsonify({'error': 'no gemini key'}), 400\n\n    from google.genai import types\n    client = genai.Client(api_key=key)\n    cfg = types.GenerateContentConfig(\n        response_modalities=['AUDIO'],\n        speech_config=types.SpeechConfig(\n            voice_config=types.VoiceConfig(\n                prebuilt_voice_config=types.PrebuiltVoiceConfig(voice_name='Kore')\n            )\n        ),\n    )\n    # 預覽版 TTS 模型偶爾會「吐文字而非音訊」導致 400 → 重試最多 3 次\n    last_err = 'unknown'\n    for _attempt in range(3):\n        try:\n            resp = client.models.generate_content(model=TTS_MODEL, contents=text, config=cfg)\n            for part in resp.candidates[0].content.parts:\n                inline = getattr(part, 'inline_data', None)\n                if inline is not None and inline.data:\n                    return Response(inline.data, mimetype='application/octet-stream')  # 24kHz 16-bit PCM\n            last_err = 'model returned text instead of audio'\n        except Exception as e:\n            last_err = str(e)\n    logger.error(f\"TTS failed after retries: {last_err}\")\n    return jsonify({'error': last_err}), 400\n\n\n# PWA：manifest 與 service worker 需從根路徑提供\n@app.route('/manifest.json')\ndef manifest():\n    return send_from_directory('static', 'manifest.json', mimetype='application/manifest+json')\n\n\n@app.route('/sw.js')\ndef service_worker():\n    resp = send_from_directory('static', 'sw.js', mimetype='application/javascript')\n    resp.headers['Service-Worker-Allowed'] = '/'\n    return resp\n\n\n# --- SocketIO Events (Gemini Live 即時模式) ---\n@socketio.on('connect')\ndef handle_connect():\n    logger.info(f\"Client connected: {request.sid}\")\n\n\n@socketio.on('disconnect')\ndef handle_disconnect():\n    sid = request.sid\n    if sid in active_sessions:\n        active_sessions[sid].stop()\n        del active_sessions[sid]\n    logger.info(f\"Client disconnected: {sid}\")\n\n\n@socketio.on('start_session')\ndef handle_start(data):\n    sid = request.sid\n    langA = data.get('langA', 'Chinese')\n    langB = data.get('langB', 'English')\n    user_key = (data.get('gemini_key') or '').strip() or None   # 選填覆蓋，留空用伺服器內建\n    instruction = (\n        f\"You are a real-time voice translator. Your ONLY job is to translate speech.\\n\"\n        f\"- When you hear {langA}, translate it to {langB} and reply in {langB}.\\n\"\n        f\"- When you hear {langB}, translate it to {langA} and reply in {langA}.\\n\"\n        f\"Rules: Output ONLY the translation. No greeting or explanation. Speak naturally.\"\n    )\n    logger.info(f\"Starting Live session: {langA} <-> {langB}\")\n    if sid in active_sessions:\n        active_sessions[sid].stop()\n    session = GeminiSession(sid, instruction, api_key=user_key)\n    active_sessions[sid] = session\n    session.start()\n    emit('status', {'msg': 'Session Started'})\n\n\n@socketio.on('stop_session')\ndef handle_stop():\n    sid = request.sid\n    if sid in active_sessions:\n        active_sessions[sid].stop()\n        del active_sessions[sid]\n\n\n@socketio.on('audio_in')\ndef handle_audio(data):\n    sid = request.sid\n    if sid in active_sessions:\n        active_sessions[sid].add_audio(data)\n\n\nif __name__ == '__main__':\n    if not API_KEY:\n        print(\"⚠️  無 Gemini 金鑰：即時模式與 Gemini 翻譯將無法使用，但 OpenAI 相容供應商仍可用。\")\n    port = int(os.getenv('PORT', '5001'))          # 雲端平台會用 PORT 環境變數指定埠號\n    debug = os.getenv('FLASK_DEBUG', '0') == '1'    # 公開部署預設關閉 debug\n    print(f\"🚀 Starting Flask Server on port {port} (debug={debug})\")\n    socketio.run(app, host='0.0.0.0', port=port, debug=debug, allow_unsafe_werkzeug=True)\n","providers.py":"\"\"\"\n翻譯供應商抽象層 (Translation Provider Layer)\n-------------------------------------------------\n統一介面，讓前端可以自由切換：\n  - \"openai\"：任何「OpenAI 相容」的服務 (OpenAI / Groq / DeepSeek / OpenRouter / Together / 本機 ...)\n  - \"gemini\"：Google Gemini\n\n前端只送 { provider, base_url, api_key, model, text, source, target }，\n後端在這裡轉發給對應供應商，金鑰不會留在瀏覽器可被第三方讀取的地方 (由 Flask 代理，順便解 CORS)。\n\"\"\"\n\nimport os\nimport json\nimport re\nimport base64\nimport requests\n\nDEFAULT_GEMINI_MODEL = \"gemini-3.5-flash\"\n# 多模態（圖片 / PDF）分析用模型：gemini-3.5-flash 為 GA 版，原生支援影像與 PDF\nDEFAULT_VISION_MODEL = \"gemini-3.5-flash\"\n\n\ndef build_prompt(source: str, target: str):\n    \"\"\"產生翻譯用的 system 指令與使用者輸入包裝。\"\"\"\n    if source and source.lower() == \"auto\":\n        system = (\n            \"You are a professional real-time translation engine for a two-way conversation. \"\n            f\"Detect the language of the input. If it is {target}, translate it into the other party's language; \"\n            f\"otherwise translate it into {target}. \"\n            \"Output ONLY the translated text — no explanations, no language labels, no quotation marks.\"\n        )\n    else:\n        system = (\n            f\"You are a professional translation engine. Translate the text from {source} into {target}. \"\n            \"Output ONLY the translated text — no explanations, no language labels, no quotation marks. \"\n            \"Preserve the tone and meaning; make it sound natural to a native speaker.\"\n        )\n    return system\n\n\ndef translate_openai(base_url: str, api_key: str, model: str, system: str, text: str, timeout: int = 30) -> str:\n    \"\"\"呼叫 OpenAI 相容的 /chat/completions 端點。\"\"\"\n    if not base_url:\n        base_url = \"https://api.openai.com/v1\"\n    url = base_url.rstrip(\"/\")\n    if not url.endswith(\"/chat/completions\"):\n        url = url + \"/chat/completions\"\n\n    headers = {\"Authorization\": f\"Bearer {api_key}\", \"Content-Type\": \"application/json\"}\n    # 注意：部分新模型（如 gpt-5.x）只支援預設 temperature，故不傳 temperature 參數\n    payload = {\n        \"model\": model or \"gpt-5.5\",\n        \"messages\": [\n            {\"role\": \"system\", \"content\": system},\n            {\"role\": \"user\", \"content\": text},\n        ],\n    }\n    r = requests.post(url, headers=headers, json=payload, timeout=timeout)\n    r.raise_for_status()\n    data = r.json()\n    return data[\"choices\"][0][\"message\"][\"content\"].strip()\n\n\ndef translate_gemini(api_key: str, model: str, system: str, text: str) -> str:\n    \"\"\"呼叫 Google Gemini 的 generate_content。\"\"\"\n    from google import genai\n    from google.genai import types\n\n    client = genai.Client(api_key=api_key)\n    resp = client.models.generate_content(\n        model=model or DEFAULT_GEMINI_MODEL,\n        contents=text,\n        config=types.GenerateContentConfig(\n            system_instruction=system,\n            temperature=0.3,\n        ),\n    )\n    return (resp.text or \"\").strip()\n\n\n# =========================================================\n# 多模態分析：拍照 / 上傳檔案 → 摘要 + 翻譯\n# =========================================================\n\ndef _vision_system(target_name: str) -> str:\n    \"\"\"產生「摘要 + 翻譯」用的 system 指令，強制 JSON 輸出。\"\"\"\n    return (\n        \"You are a visual & document translation assistant. \"\n        \"The input may be a photo or file containing a menu, sign, form, article, or any text.\\n\"\n        \"Do the following:\\n\"\n        \"1. Read and understand all meaningful text and visual information in the input.\\n\"\n        f\"2. Write a concise, well-organized summary of the key points, written in {target_name}.\\n\"\n        f\"3. Provide a faithful, natural full translation of the text content into {target_name}.\\n\"\n        'Respond with ONLY a JSON object of the exact shape '\n        '{\"summary\": \"...\", \"translation\": \"...\"}. '\n        \"No markdown, no code fences, no extra commentary. \"\n        \"If there is no readable text, explain that in the summary and use an empty string for translation.\"\n    )\n\n\ndef _parse_json_result(raw: str) -> dict:\n    \"\"\"把 LLM 回傳解析成 {summary, translation}，容忍 code fence 或被截斷的 JSON。\"\"\"\n    raw = (raw or \"\").strip()\n    if raw.startswith(\"```\"):\n        raw = re.sub(r\"^```[a-zA-Z]*\\n?\", \"\", raw)\n        raw = re.sub(r\"\\n?```$\", \"\", raw).strip()\n    try:\n        obj = json.loads(raw)\n        return {\n            \"summary\": (obj.get(\"summary\") or \"\").strip(),\n            \"translation\": (obj.get(\"translation\") or \"\").strip(),\n        }\n    except Exception:\n        pass\n\n    # 容忍截斷（超長文件可能超出輸出上限）：用正則救回 summary / translation 欄位\n    def grab(key):\n        m = re.search(r'\"' + key + r'\"\\s*:\\s*\"((?:[^\"\\\\]|\\\\.)*)', raw)\n        if not m:\n            return \"\"\n        frag = m.group(1)\n        try:\n            return json.loads('\"' + frag + '\"')   # 還原 JSON 跳脫字元\n        except Exception:\n            return frag\n    summary, translation = grab(\"summary\"), grab(\"translation\")\n    if summary or translation:\n        return {\"summary\": summary.strip(), \"translation\": translation.strip()}\n    return {\"summary\": \"\", \"translation\": raw}\n\n\ndef _analyze_gemini(api_key: str, model: str, system: str,\n                    text: str, file_bytes: bytes, mime_type: str) -> str:\n    \"\"\"Gemini 多模態：圖片 / PDF 原生讀取，回傳原始 JSON 字串。\"\"\"\n    from google import genai\n    from google.genai import types\n\n    if model and not model.startswith(\"gemini\"):\n        model = \"\"   # 避免把 OpenAI 模型名誤送給 Gemini\n\n    client = genai.Client(api_key=api_key)\n    parts = []\n    if file_bytes is not None:\n        parts.append(types.Part.from_bytes(data=file_bytes, mime_type=mime_type or \"application/octet-stream\"))\n    if text:\n        parts.append(text)\n    if not parts:\n        return \"\"\n\n    resp = client.models.generate_content(\n        model=model or DEFAULT_VISION_MODEL,\n        contents=parts,\n        config=types.GenerateContentConfig(\n            system_instruction=system,\n            temperature=0.3,\n            response_mime_type=\"application/json\",\n            max_output_tokens=8192,\n            # 關閉 thinking：OCR/摘要/翻譯不需推理，且能避免思考 token 吃掉輸出額度導致 JSON 被截斷\n            thinking_config=types.ThinkingConfig(thinking_budget=0),\n        ),\n    )\n    return resp.text or \"\"\n\n\ndef _analyze_openai(base_url: str, api_key: str, model: str, system: str,\n                    text: str, file_bytes: bytes, mime_type: str, timeout: int = 90) -> str:\n    \"\"\"OpenAI 相容多模態（vision）：圖片以 data URL 塞進 content，回傳原始 JSON 字串。\"\"\"\n    if not base_url:\n        base_url = \"https://api.openai.com/v1\"\n    url = base_url.rstrip(\"/\")\n    if not url.endswith(\"/chat/completions\"):\n        url = url + \"/chat/completions\"\n\n    content = []\n    if text:\n        content.append({\"type\": \"text\", \"text\": text})\n    if file_bytes is not None:\n        b64 = base64.b64encode(file_bytes).decode()\n        data_url = f\"data:{mime_type or 'image/jpeg'};base64,{b64}\"\n        content.append({\"type\": \"image_url\", \"image_url\": {\"url\": data_url}})\n    if not content:\n        content = [{\"type\": \"text\", \"text\": \"\"}]\n\n    headers = {\"Authorization\": f\"Bearer {api_key}\", \"Content-Type\": \"application/json\"}\n    # 不傳 temperature / max_tokens：盡量相容各家 (OpenAI/Groq/DeepSeek/OpenRouter…)；截斷由解析器容錯\n    payload = {\n        \"model\": model or \"gpt-5.5\",\n        \"messages\": [\n            {\"role\": \"system\", \"content\": system},\n            {\"role\": \"user\", \"content\": content},\n        ],\n    }\n    r = requests.post(url, headers=headers, json=payload, timeout=timeout)\n    r.raise_for_status()\n    data = r.json()\n    return data[\"choices\"][0][\"message\"][\"content\"] or \"\"\n\n\ndef analyze(provider: str, api_key: str, model: str, target_name: str,\n            base_url: str = \"\", text: str = None,\n            file_bytes: bytes = None, mime_type: str = None) -> dict:\n    \"\"\"\n    多模態分析 → {summary, translation}，依 provider 走 Gemini 或 OpenAI 相容。\n      - file_bytes + mime_type：圖片 (或 PDF，僅 Gemini 支援原生讀取)\n      - text：純文字內容\n    \"\"\"\n    system = _vision_system(target_name)\n    provider = (provider or \"gemini\").lower()\n    if provider == \"openai\":\n        raw = _analyze_openai(base_url, api_key, model, system, text, file_bytes, mime_type)\n    else:\n        raw = _analyze_gemini(api_key, model, system, text, file_bytes, mime_type)\n    return _parse_json_result(raw)\n\n\ndef generate(provider: str, api_key: str, model: str, base_url: str, system: str, user: str) -> str:\n    \"\"\"通用單輪生成（system + user → text），依 provider 分派。供旅遊問答等使用。\"\"\"\n    provider = (provider or \"gemini\").lower()\n    if provider == \"openai\":\n        return translate_openai(base_url, api_key, model, system, user, timeout=45)\n    if model and not model.startswith(\"gemini\"):\n        model = \"\"\n    return translate_gemini(api_key, model, system, user)\n\n\ndef translate(data: dict) -> dict:\n    \"\"\"\n    主入口。data 需含：\n      provider: \"openai\" | \"gemini\"\n      text:     要翻譯的文字\n      source:   來源語言 (英文名，或 \"auto\")\n      target:   目標語言 (英文名)\n      base_url / api_key / model：供應商設定 (openai 必填 key；gemini 可用伺服器 .env 的 key 當後備)\n    回傳 { ok, translation } 或 { ok:false, error }\n    \"\"\"\n    provider = (data.get(\"provider\") or \"gemini\").lower()\n    text = (data.get(\"text\") or \"\").strip()\n    source = data.get(\"source\") or \"auto\"\n    target = data.get(\"target\") or \"English\"\n\n    if not text:\n        return {\"ok\": False, \"error\": \"empty text\"}\n\n    system = build_prompt(source, target)\n\n    try:\n        if provider == \"openai\":\n            api_key = data.get(\"api_key\") or \"\"\n            if not api_key:\n                return {\"ok\": False, \"error\": \"OpenAI 相容供應商需要 API Key\"}\n            out = translate_openai(\n                base_url=data.get(\"base_url\", \"\"),\n                api_key=api_key,\n                model=data.get(\"model\", \"\"),\n                system=system,\n                text=text,\n            )\n        else:  # gemini\n            api_key = data.get(\"api_key\") or os.getenv(\"GEMINI_API_KEY\") or os.getenv(\"GOOGLE_API_KEY\") or \"\"\n            if not api_key:\n                return {\"ok\": False, \"error\": \"找不到 Gemini API Key（.env 或設定皆無）\"}\n            out = translate_gemini(\n                api_key=api_key,\n                model=data.get(\"model\", \"\"),\n                system=system,\n                text=text,\n            )\n        return {\"ok\": True, \"translation\": out, \"provider\": provider}\n    except requests.HTTPError as e:\n        body = \"\"\n        try:\n            body = e.response.text[:300]\n        except Exception:\n            pass\n        return {\"ok\": False, \"error\": f\"HTTP {e.response.status_code if e.response else '?'}: {body}\"}\n    except Exception as e:\n        return {\"ok\": False, \"error\": f\"{type(e).__name__}: {e}\"}\n","requirements.txt":"google-genai\nflask\nflask-socketio\nsimple-websocket\npython-dotenv\nrequests\n","render.yaml":"services:\n  - type: web\n    name: liang-translator\n    runtime: python\n    plan: free\n    buildCommand: pip install -r requirements.txt\n    startCommand: python app.py\n    envVars:\n      - key: GEMINI_API_KEY      # 在 Render 儀表板填入，不寫進 repo（加密保存）\n        sync: false\n      - key: TAVILY_API_KEY      # 選填：旅遊助手上網查資料。在 Render 儀表板填入即可全裝置生效\n        sync: false\n      - key: FLASK_DEBUG\n        value: \"0\"\n      - key: PYTHON_VERSION\n        value: \"3.12.10\"\n","runtime.txt":"python-3.12.10\n",".gitignore":"# 金鑰檔絕不提交 (改用部署平台的環境變數)\n.env\n\n# Python\n__pycache__/\n*.pyc\n*.pyo\n\n# 記錄與暫存\n*.log\n_uitest.py\nshot_*.png\n\n# 前端相依\nnode_modules/\n.DS_Store\n\n# 參考截圖不公開\n參考/\n\n# 使用卡含金鑰，不上傳\n*.pdf\n",".env.example":"# 複製此檔為 .env 並填入你的金鑰。.env 已被 .gitignore 排除，不會上傳。\n# 雲端部署時，請在平台（例如 Render）的環境變數設定 GEMINI_API_KEY，不要寫進程式碼。\nGEMINI_API_KEY=your_gemini_api_key_here\nGOOGLE_API_KEY=your_gemini_api_key_here\n# 選填：旅遊助手上網查資料（Tavily）。也可改在 App 設定裡填。留空則問答退回用 AI 既有知識。\nTAVILY_API_KEY=your_tavily_api_key_here\n","templates/index.html":"<!DOCTYPE html>\n<html lang=\"zh-TW\">\n\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no\">\n    <meta name=\"theme-color\" content=\"#2a1a4a\">\n    <title>亮言 · 即時翻譯</title>\n    <link rel=\"manifest\" href=\"/manifest.json\">\n    <link rel=\"stylesheet\" href=\"{{ url_for('static', filename='css/style.css') }}\">\n    <link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\n    <link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin>\n    <link href=\"https://fonts.googleapis.com/css2?family=Noto+Sans+TC:wght@400;500;700;900&display=swap\" rel=\"stylesheet\">\n    <script src=\"https://cdnjs.cloudflare.com/ajax/libs/socket.io/4.7.2/socket.io.min.js\"></script>\n    <!-- OpenCC：手機語音辨識常把國語轉成簡體，載入後把辨識結果轉回繁體 -->\n    <script src=\"https://cdn.jsdelivr.net/npm/opencc-js@1.0.5/dist/umd/full.min.js\"></script>\n\n<style>\n/* ===== Password Gate ===== */\n.password-gate {\n    position: fixed;\n    top: 0;\n    left: 0;\n    width: 100%;\n    height: 100%;\n    background: linear-gradient(135deg, #1a1a2e 0%, #16213e 50%, #0f3460 100%);\n    z-index: 99999;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    transition: opacity 0.6s ease, transform 0.6s ease;\n}\n\n.password-gate.hidden {\n    opacity: 0;\n    transform: scale(1.05);\n    pointer-events: none;\n}\n\n.gate-box {\n    background: rgba(255, 255, 255, 0.06);\n    backdrop-filter: blur(20px);\n    -webkit-backdrop-filter: blur(20px);\n    border: 1px solid rgba(255, 255, 255, 0.12);\n    border-radius: 24px;\n    padding: 50px 45px;\n    width: 90%;\n    max-width: 440px;\n    text-align: center;\n    animation: gateIn 0.8s ease;\n}\n\n@keyframes gateIn {\n    from { opacity: 0; transform: translateY(30px) scale(0.95); }\n    to { opacity: 1; transform: translateY(0) scale(1); }\n}\n\n.gate-logo {\n    font-size: 64px;\n    margin-bottom: 10px;\n    animation: gateFloat 3s ease-in-out infinite;\n}\n\n@keyframes gateFloat {\n    0%, 100% { transform: translateY(0); }\n    50% { transform: translateY(-12px); }\n}\n\n.gate-title {\n    color: #fff;\n    font-size: 24px;\n    font-weight: 700;\n    margin-bottom: 6px;\n}\n\n.gate-subtitle {\n    color: rgba(255, 255, 255, 0.6);\n    font-size: 14px;\n    margin-bottom: 8px;\n}\n\n.gate-disclaimer {\n    font-size: 0.7rem;\n    color: rgba(255, 255, 255, 0.3);\n    margin-bottom: 24px;\n}\n\n.gate-input-wrap {\n    position: relative;\n    margin-bottom: 18px;\n}\n\n.gate-input {\n    width: 100%;\n    padding: 14px 50px 14px 20px;\n    border-radius: 14px;\n    border: 1px solid rgba(255, 255, 255, 0.2);\n    background: rgba(255, 255, 255, 0.08);\n    color: #fff;\n    font-size: 16px;\n    font-family: inherit;\n    outline: none;\n    transition: border-color 0.3s ease, box-shadow 0.3s ease;\n}\n\n.gate-input:focus {\n    border-color: #f5c451;\n    box-shadow: 0 0 0 3px #f5c45133;\n}\n\n.gate-input::placeholder {\n    color: rgba(255, 255, 255, 0.35);\n}\n\n.gate-toggle-pw {\n    position: absolute;\n    right: 14px;\n    top: 50%;\n    transform: translateY(-50%);\n    background: none;\n    border: none;\n    color: rgba(255, 255, 255, 0.5);\n    cursor: pointer;\n    font-size: 18px;\n    padding: 4px;\n}\n\n.gate-btn {\n    width: 100%;\n    padding: 14px;\n    border-radius: 14px;\n    border: none;\n    background: linear-gradient(135deg, #f5c451, #f7d98a);\n    color: #fff;\n    font-size: 16px;\n    font-weight: 700;\n    font-family: inherit;\n    cursor: pointer;\n    transition: all 0.3s ease;\n    box-shadow: 0 4px 15px #f5c45140;\n}\n\n.gate-btn:hover {\n    transform: translateY(-2px);\n    box-shadow: 0 8px 25px #f5c45150;\n}\n\n.gate-error {\n    color: #ff6b6b;\n    font-size: 14px;\n    margin-top: 12px;\n    min-height: 20px;\n}\n\n.gate-admin-toggle {\n    margin-top: 24px;\n    color: rgba(255, 255, 255, 0.35);\n    font-size: 13px;\n    cursor: pointer;\n    transition: color 0.3s ease;\n    user-select: none;\n}\n\n.gate-admin-toggle:hover {\n    color: rgba(255, 255, 255, 0.6);\n}\n\n.admin-panel {\n    display: none;\n    margin-top: 20px;\n    padding: 20px;\n    border-radius: 14px;\n    background: rgba(255, 255, 255, 0.05);\n    border: 1px solid rgba(255, 255, 255, 0.1);\n    text-align: left;\n}\n\n.admin-panel.show { display: block; }\n\n.admin-panel h4 {\n    color: rgba(255, 255, 255, 0.8);\n    font-size: 14px;\n    margin-bottom: 12px;\n}\n\n.admin-pw-list {\n    list-style: none;\n    margin: 0;\n    padding: 0;\n    max-height: 120px;\n    overflow-y: auto;\n    margin-bottom: 12px;\n}\n\n.admin-pw-list li {\n    display: flex;\n    justify-content: space-between;\n    align-items: center;\n    padding: 6px 10px;\n    border-radius: 8px;\n    color: rgba(255, 255, 255, 0.7);\n    font-size: 13px;\n    font-family: 'Courier New', monospace;\n}\n\n.admin-pw-list li:hover {\n    background: rgba(255, 255, 255, 0.05);\n}\n\n.admin-pw-list li button {\n    background: rgba(255, 80, 80, 0.3);\n    border: none;\n    color: #ff6b6b;\n    padding: 2px 10px;\n    border-radius: 6px;\n    cursor: pointer;\n    font-size: 12px;\n}\n\n.admin-add-row {\n    display: flex;\n    gap: 8px;\n}\n\n.admin-add-row input {\n    flex: 1;\n    padding: 8px 12px;\n    border-radius: 8px;\n    border: 1px solid rgba(255, 255, 255, 0.15);\n    background: rgba(255, 255, 255, 0.06);\n    color: #fff;\n    font-size: 13px;\n    font-family: inherit;\n    outline: none;\n}\n\n.admin-add-row button {\n    padding: 8px 16px;\n    border-radius: 8px;\n    border: none;\n    background: linear-gradient(135deg, #f5c451, #f7d98a);\n    color: #fff;\n    font-size: 13px;\n    font-weight: 600;\n    cursor: pointer;\n}\n\n.admin-msg {\n    color: rgba(255, 255, 255, 0.6);\n    font-size: 12px;\n    margin-top: 8px;\n    min-height: 16px;\n}\n\n</style>\n</head>\n\n<body>\n<!-- Password Gate (SHA-256) -->\n<div class=\"password-gate\" id=\"passwordGate\">\n    <div class=\"gate-box\">\n        <div class=\"gate-logo\">🌐</div>\n        <div class=\"gate-title\">亮言 · 即時翻譯</div>\n        <div class=\"gate-subtitle\">請輸入密碼以進入使用</div>\n        <p class=\"gate-disclaimer\">本機制僅為閱讀阻擋，非安全保護措施</p>\n\n        <div class=\"gate-input-wrap\">\n            <input type=\"password\" class=\"gate-input\" id=\"pwInput\" placeholder=\"請輸入密碼...\" autocomplete=\"off\">\n            <button class=\"gate-toggle-pw\" id=\"togglePw\" title=\"顯示/隱藏密碼\">&#128065;</button>\n        </div>\n        <button class=\"gate-btn\" id=\"pwSubmit\">進入</button>\n        <div class=\"gate-error\" id=\"pwError\"></div>\n\n        <div class=\"gate-admin-toggle\" id=\"adminToggle\">&#128274; 管理員</div>\n        <div class=\"admin-panel\" id=\"adminPanel\">\n            <h4>密碼管理（需管理員密碼）</h4>\n            <div class=\"gate-input-wrap\" style=\"margin-bottom:12px;\">\n                <input type=\"password\" class=\"gate-input\" id=\"adminPwInput\" placeholder=\"管理員密碼...\" style=\"font-size:14px;padding:10px 16px;\">\n            </div>\n            <div id=\"adminContent\" style=\"display:none;\">\n                <ul class=\"admin-pw-list\" id=\"pwList\"></ul>\n                <div class=\"admin-add-row\">\n                    <input type=\"text\" id=\"newPwInput\" placeholder=\"新增密碼...\">\n                    <button id=\"addPwBtn\">新增</button>\n                </div>\n                <div class=\"admin-msg\" id=\"adminMsg\"></div>\n                <button class=\"gate-btn\" id=\"enterSiteBtn\" style=\"margin-top:12px;font-size:14px;padding:10px;\">進入網站</button>\n            </div>\n        </div>\n    </div>\n</div>\n\n    <div class=\"app\">\n        <!-- 頂部列 -->\n        <header class=\"topbar\">\n            <div class=\"brand\">\n                <span class=\"dot\" id=\"statusDot\" title=\"連線狀態\"></span>\n                <h1>亮言 · 即時翻譯</h1>\n            </div>\n            <div class=\"top-actions\">\n                <button class=\"icon-btn\" id=\"modeBtn\" title=\"切換模式\">👤 單人</button>\n                <button class=\"icon-btn\" id=\"historyBtn\" title=\"歷史紀錄\">🕐</button>\n                <button class=\"icon-btn\" id=\"settingsBtn\" title=\"設定\">⚙️</button>\n            </div>\n        </header>\n\n        <!-- ===== 單人模式 ===== -->\n        <section id=\"singleView\" class=\"view\">\n            <div class=\"lang-bar\">\n                <select class=\"lang-select\" id=\"s_langA\"></select>\n                <button class=\"swap-btn\" id=\"s_swap\" title=\"對調語言\">⇄</button>\n                <select class=\"lang-select\" id=\"s_langB\"></select>\n            </div>\n\n            <div class=\"result-box\" id=\"s_result\">\n                <span class=\"placeholder\">翻譯結果會顯示在這裡…</span>\n            </div>\n\n            <div class=\"visualizer\" id=\"s_viz\">\n                <span></span><span></span><span></span><span></span><span></span>\n                <span></span><span></span><span></span><span></span><span></span>\n            </div>\n\n            <div class=\"engine-row\">\n                <label class=\"engine-pill\">\n                    <input type=\"radio\" name=\"engine\" value=\"stt\" checked> 逐句 (STT→翻譯→朗讀 · 支援所有供應商)\n                </label>\n                <label class=\"engine-pill\">\n                    <input type=\"radio\" name=\"engine\" value=\"live\"> 即時 (Gemini Live · 低延遲)\n                </label>\n            </div>\n\n            <button id=\"s_mic\" class=\"mic-btn\"><span class=\"mic-ico\">🎤</span><span class=\"mic-label\">點一下開始說話</span></button>\n\n            <div class=\"text-row\">\n                <textarea id=\"s_text\" maxlength=\"200\" placeholder=\"或直接輸入要翻譯的文字…\"></textarea>\n                <div class=\"text-meta\">\n                    <span id=\"s_count\">0/200</span>\n                    <button id=\"s_send\" class=\"send-btn\">翻譯 ➤</button>\n                </div>\n            </div>\n\n            <!-- 拍照 / 上傳檔案：摘要 + 翻譯 -->\n            <div class=\"tool-row\">\n                <button id=\"s_camera\" class=\"tool-btn\">📷 拍照翻譯</button>\n                <button id=\"s_file\" class=\"tool-btn\">📎 上傳檔案</button>\n            </div>\n            <!-- 旅遊小工具 -->\n            <div class=\"tool-row\">\n                <button id=\"s_weather\" class=\"tool-btn\">🌤️ 天氣</button>\n                <button id=\"s_currency\" class=\"tool-btn\">💱 匯率</button>\n                <button id=\"s_ask\" class=\"tool-btn\">🧭 助手</button>\n            </div>\n        </section>\n\n        <!-- 隱藏的檔案輸入 -->\n        <input type=\"file\" id=\"cameraInput\" accept=\"image/*\" capture=\"environment\" hidden>\n        <input type=\"file\" id=\"fileInput\" accept=\"image/*,application/pdf,text/plain,.pdf,.txt,.md,.csv\" hidden>\n\n        <!-- ===== 面對面模式 ===== -->\n        <section id=\"faceView\" class=\"view hidden\">\n            <!-- 上半：翻轉 180°，給對面的人看 -->\n            <div class=\"face-panel top\" id=\"face_top\">\n                <div class=\"face-inner\">\n                    <select class=\"lang-select\" id=\"f_langTop\"></select>\n                    <div class=\"result-box face-result\" id=\"f_resultTop\">\n                        <span class=\"placeholder\">對方語言的翻譯會顯示在這裡…</span>\n                    </div>\n                    <button class=\"mic-btn face-mic\" id=\"f_micTop\"><span class=\"mic-ico\">🎤</span> 說話</button>\n                </div>\n            </div>\n\n            <div class=\"face-divider\"><span>面對面 · 手機平放桌上</span></div>\n\n            <!-- 下半：正常方向，給你看 -->\n            <div class=\"face-panel bottom\" id=\"face_bottom\">\n                <div class=\"face-inner\">\n                    <select class=\"lang-select\" id=\"f_langBottom\"></select>\n                    <div class=\"result-box face-result\" id=\"f_resultBottom\">\n                        <span class=\"placeholder\">你的語言的翻譯會顯示在這裡…</span>\n                    </div>\n                    <button class=\"mic-btn face-mic\" id=\"f_micBottom\"><span class=\"mic-ico\">🎤</span> 說話</button>\n                </div>\n            </div>\n        </section>\n    </div>\n\n    <!-- ===== 設定 Modal ===== -->\n    <div class=\"modal hidden\" id=\"settingsModal\">\n        <div class=\"modal-card\">\n            <h2>設定</h2>\n\n            <h3>翻譯後端 (雲端 API)</h3>\n            <p class=\"hint\">選 Gemini 用內建金鑰；選 OpenAI 相容可接 OpenAI / Groq / DeepSeek / OpenRouter…任何相容服務。拍照／檔案翻譯也會跟隨此設定；但 PDF 僅 Gemini 能讀，選其他供應商時 PDF 會自動改用 Gemini。</p>\n            <label>供應商\n                <select id=\"cfg_provider\">\n                    <option value=\"gemini\">Gemini (Google)</option>\n                    <option value=\"openai\">OpenAI 相容 (自訂)</option>\n                </select>\n            </label>\n            <div id=\"openaiFields\">\n                <label>相容 OpenAI 格式的網址\n                    <input type=\"text\" id=\"cfg_baseurl\" placeholder=\"https://api.openai.com/v1\">\n                </label>\n                <label>API 金鑰 (API Key)\n                    <input type=\"password\" id=\"cfg_apikey\" placeholder=\"sk-...\">\n                </label>\n            </div>\n            <label>模型名稱 (Model)\n                <input type=\"text\" id=\"cfg_model\" placeholder=\"gemini-3.5-flash 或 gpt-5.5\">\n            </label>\n\n            <h3>🔑 API 金鑰（集中管理）</h3>\n            <p class=\"hint\">第三方服務的金鑰統一放這裡。留空的用免金鑰來源或伺服器內建。</p>\n            <label>Gemini 金鑰（選填，留空用伺服器內建）\n                <input type=\"password\" id=\"cfg_geminikey\" placeholder=\"AIza...（放伺服器較安全，這裡是選填覆蓋）\">\n            </label>\n            <label>Tavily 金鑰（旅遊問答上網查資料）\n                <input type=\"password\" id=\"cfg_tavilykey\" placeholder=\"tvly-...\">\n            </label>\n            <label>OpenWeatherMap 金鑰（選填；天氣預設免金鑰用 Open-Meteo）\n                <input type=\"password\" id=\"cfg_owmkey\" placeholder=\"留空即可，免金鑰照樣查天氣\">\n            </label>\n\n            <h3>語音朗讀 (TTS)</h3>\n            <label>語速 <input type=\"range\" id=\"cfg_rate\" min=\"0.5\" max=\"1.5\" step=\"0.1\" value=\"1\"></label>\n            <label class=\"check\"><input type=\"checkbox\" id=\"cfg_autospeak\" checked> 翻譯完成後自動朗讀</label>\n\n            <div class=\"modal-actions\">\n                <button class=\"ghost\" id=\"cfg_cancel\">取消</button>\n                <button class=\"primary\" id=\"cfg_save\">儲存</button>\n            </div>\n        </div>\n    </div>\n\n    <!-- ===== 拍照 / 檔案：摘要+翻譯 Modal ===== -->\n    <div class=\"modal hidden\" id=\"visionModal\">\n        <div class=\"modal-card\">\n            <h2 id=\"visionTitle\">📷 拍照翻譯</h2>\n            <label>翻譯成\n                <select id=\"vision_target\"></select>\n            </label>\n            <div id=\"visionPreview\" class=\"vision-preview hidden\"></div>\n            <div id=\"visionStatus\" class=\"vision-status hint\"></div>\n            <div id=\"visionResult\" class=\"vision-result hidden\">\n                <div class=\"vision-section\">\n                    <h3>📌 摘要</h3>\n                    <div id=\"visionSummary\" class=\"vision-text\"></div>\n                </div>\n                <div class=\"vision-section\">\n                    <h3>🌐 翻譯</h3>\n                    <div id=\"visionTranslation\" class=\"vision-text\"></div>\n                </div>\n            </div>\n            <div class=\"modal-actions\">\n                <button class=\"ghost\" id=\"vision_close\">關閉</button>\n                <button class=\"primary\" id=\"vision_speak\">🔊 朗讀</button>\n            </div>\n        </div>\n    </div>\n\n    <!-- ===== 天氣 Modal ===== -->\n    <div class=\"modal hidden\" id=\"weatherModal\">\n        <div class=\"modal-card\">\n            <h2>🌤️ 天氣查詢</h2>\n            <p class=\"hint\">免費、免金鑰（Open-Meteo）。輸入地點或用目前位置。</p>\n            <div class=\"wx-search\">\n                <input type=\"text\" id=\"wx_place\" placeholder=\"例如：那霸、東京、台北…\">\n                <button class=\"primary\" id=\"wx_go\">查詢</button>\n            </div>\n            <button class=\"ghost wx-geo\" id=\"wx_geo\">📍 用目前位置</button>\n            <div id=\"wx_result\" class=\"wx-result hidden\"></div>\n            <div id=\"wx_status\" class=\"hint\"></div>\n            <div class=\"modal-actions\">\n                <button class=\"ghost\" id=\"wx_close\">關閉</button>\n            </div>\n        </div>\n    </div>\n\n    <!-- ===== 旅遊助手 Modal ===== -->\n    <div class=\"modal hidden\" id=\"askModal\">\n        <div class=\"modal-card\">\n            <h2>🧭 旅遊助手</h2>\n            <p class=\"hint\">打一句話問任何旅遊問題。填了 Tavily 金鑰會先上網查最新，否則用 AI 既有知識回答。</p>\n            <textarea id=\"ask_q\" rows=\"3\" placeholder=\"例如：沖繩 12 月適合玩水嗎？那霸機場到國際通怎麼去？\"></textarea>\n            <div class=\"modal-actions\" style=\"margin-top:10px;\">\n                <button class=\"primary\" id=\"ask_go\">送出</button>\n            </div>\n            <div id=\"ask_status\" class=\"hint\"></div>\n            <div id=\"ask_answer\" class=\"vision-text hidden\" style=\"margin-top:10px;\"></div>\n            <div id=\"ask_sources\" class=\"ask-sources\"></div>\n            <div class=\"modal-actions\">\n                <button class=\"ghost\" id=\"ask_close\">關閉</button>\n                <button class=\"primary\" id=\"ask_speak\">🔊 朗讀</button>\n            </div>\n        </div>\n    </div>\n\n    <!-- ===== 匯率換算 Modal ===== -->\n    <div class=\"modal hidden\" id=\"currencyModal\">\n        <div class=\"modal-card\">\n            <h2>💱 匯率換算</h2>\n            <p class=\"hint\">即時匯率（歐洲央行／ER-API，免費）。點金額或幣別會自動換算。</p>\n            <label>金額\n                <input type=\"number\" id=\"cur_amount\" inputmode=\"decimal\" value=\"1\" min=\"0\" step=\"any\">\n            </label>\n            <div class=\"cur-row\">\n                <select class=\"lang-select\" id=\"cur_from\"></select>\n                <button class=\"swap-btn\" id=\"cur_swap\" title=\"對調幣別\">⇄</button>\n                <select class=\"lang-select\" id=\"cur_to\"></select>\n            </div>\n            <div class=\"cur-result\" id=\"cur_result\">—</div>\n            <div class=\"cur-rate hint\" id=\"cur_rate\"></div>\n            <div class=\"modal-actions\">\n                <button class=\"ghost\" id=\"cur_close\">關閉</button>\n                <button class=\"primary\" id=\"cur_convert\">換算</button>\n            </div>\n        </div>\n    </div>\n\n    <!-- ===== 歷史 Modal ===== -->\n    <div class=\"modal hidden\" id=\"historyModal\">\n        <div class=\"modal-card\">\n            <h2>歷史紀錄</h2>\n            <div id=\"historyList\" class=\"history-list\"></div>\n            <div class=\"modal-actions\">\n                <button class=\"ghost\" id=\"hist_clear\">清空</button>\n                <button class=\"primary\" id=\"hist_close\">關閉</button>\n            </div>\n        </div>\n    </div>\n\n    <div id=\"toast\" class=\"toast hidden\"></div>\n\n    <script src=\"{{ url_for('static', filename='js/app.js') }}\"></script>\n\n<script>\n// === Password Gate (SHA-256, 閱讀阻擋用途，非安全保護) ===\n(function () {\n  'use strict';\n  var ADMIN_HASH       = '3ee7f6541f8186b90ad66c06d6e5bf89ca81c3c16c07b48800d751ac21adcd23';\n  // 內建（寫死於程式碼）的使用者密碼雜湊清單；新增請改原始碼並重新部署\n  var BUILTIN_HASHES   = [\"3ee7f6541f8186b90ad66c06d6e5bf89ca81c3c16c07b48800d751ac21adcd23\"];\n  var HASH_STORAGE     = 'liang_translate_pw';\n  var AUTH_KEY         = 'liang_translate_authed';\n\n  var gate = document.getElementById('passwordGate');\n  if (!gate) return;\n\n  if (sessionStorage.getItem(AUTH_KEY) === '1') {\n    gate.classList.add('hidden');\n    setTimeout(function () { gate.style.display = 'none'; }, 600);\n    return;\n  }\n\n  var pwInput      = document.getElementById('pwInput');\n  var pwSubmit     = document.getElementById('pwSubmit');\n  var pwError      = document.getElementById('pwError');\n  var togglePw     = document.getElementById('togglePw');\n  var adminToggle  = document.getElementById('adminToggle');\n  var adminPanel   = document.getElementById('adminPanel');\n  var adminPwInput = document.getElementById('adminPwInput');\n  var adminContent = document.getElementById('adminContent');\n  var pwList       = document.getElementById('pwList');\n  var newPwInput   = document.getElementById('newPwInput');\n  var addPwBtn     = document.getElementById('addPwBtn');\n  var enterSiteBtn = document.getElementById('enterSiteBtn');\n  var adminMsg     = document.getElementById('adminMsg');\n\n  function sha256(str) {\n    var encoder = new TextEncoder();\n    return crypto.subtle.digest('SHA-256', encoder.encode(str)).then(function (buf) {\n      return Array.from(new Uint8Array(buf)).map(function (b) {\n        return b.toString(16).padStart(2, '0');\n      }).join('');\n    });\n  }\n\n  // 只回傳「管理員另外加在 localStorage 的密碼」，內建密碼一律走 BUILTIN_HASHES\n  function getExtraHashes() {\n    try {\n      var raw = localStorage.getItem(HASH_STORAGE);\n      if (!raw) return [];\n      var parsed = JSON.parse(raw);\n      if (!Array.isArray(parsed)) return [];\n      // 過濾掉舊格式（明文或不是 64 字元 hex）與已在內建清單中的雜湊\n      return parsed.filter(function (h) {\n        return typeof h === 'string' && h.length === 64 && BUILTIN_HASHES.indexOf(h) === -1;\n      });\n    } catch (e) { return []; }\n  }\n\n  function saveExtraHashes(list) {\n    localStorage.setItem(HASH_STORAGE, JSON.stringify(list));\n  }\n\n  function enterSite() {\n    sessionStorage.setItem(AUTH_KEY, '1');\n    gate.classList.add('hidden');\n    setTimeout(function () { gate.style.display = 'none'; }, 600);\n  }\n\n  if (togglePw) {\n    togglePw.addEventListener('click', function () {\n      pwInput.type = pwInput.type === 'password' ? 'text' : 'password';\n    });\n  }\n\n  function checkPassword() {\n    var val = pwInput.value.trim();\n    if (!val) {\n      pwError.textContent = '請輸入密碼';\n      return;\n    }\n    sha256(val).then(function (hash) {\n      var extras = getExtraHashes();\n      // 進入密碼優先：任何有效密碼（含管理密碼）直接進入，管理面板另由「管理員」開啟\n      if (BUILTIN_HASHES.indexOf(hash) !== -1 || extras.indexOf(hash) !== -1 || hash === ADMIN_HASH) {\n        enterSite();\n      } else {\n        pwError.textContent = '密碼錯誤，請重新輸入';\n        pwInput.value = '';\n        pwInput.focus();\n      }\n    });\n  }\n\n  pwSubmit.addEventListener('click', checkPassword);\n  pwInput.addEventListener('keydown', function (e) {\n    if (e.key === 'Enter') checkPassword();\n  });\n\n  if (adminToggle) {\n    adminToggle.addEventListener('click', function () {\n      adminPanel.classList.toggle('show');\n    });\n  }\n\n  if (adminPwInput) {\n    var debounce = null;\n    adminPwInput.addEventListener('input', function () {\n      clearTimeout(debounce);\n      debounce = setTimeout(function () {\n        sha256(adminPwInput.value).then(function (hash) {\n          if (hash === ADMIN_HASH) {\n            if (adminContent) adminContent.style.display = 'block';\n            renderHashList();\n          } else {\n            if (adminContent) adminContent.style.display = 'none';\n          }\n        });\n      }, 200);\n    });\n  }\n\n  function renderHashList() {\n    if (!pwList) return;\n    var extras = getExtraHashes();\n    pwList.innerHTML = '';\n\n    // 內建密碼（不可刪）\n    BUILTIN_HASHES.forEach(function (h) {\n      var li = document.createElement('li');\n      var span = document.createElement('span');\n      span.textContent = h.substring(0, 8) + '...' + h.substring(60) + '（內建）';\n      span.title = h + '（內建，需改原始碼才能刪除）';\n      li.appendChild(span);\n      pwList.appendChild(li);\n    });\n\n    // 管理員額外加的（可刪）\n    extras.forEach(function (h, i) {\n      var li = document.createElement('li');\n      var span = document.createElement('span');\n      span.textContent = h.substring(0, 8) + '...' + h.substring(60);\n      span.title = h;\n      li.appendChild(span);\n      var btn = document.createElement('button');\n      btn.textContent = '刪除';\n      btn.addEventListener('click', function () {\n        var current = getExtraHashes();\n        if (i < 0 || i >= current.length) return;\n        current.splice(i, 1);\n        saveExtraHashes(current);\n        renderHashList();\n        if (adminMsg) {\n          adminMsg.textContent = '已刪除';\n          setTimeout(function () { adminMsg.textContent = ''; }, 2000);\n        }\n      });\n      li.appendChild(btn);\n      pwList.appendChild(li);\n    });\n  }\n\n  function addPassword() {\n    var val = newPwInput.value.trim();\n    if (!val) { if (adminMsg) adminMsg.textContent = '請輸入密碼'; return; }\n    sha256(val).then(function (hash) {\n      if (hash === ADMIN_HASH) { if (adminMsg) adminMsg.textContent = '不可新增管理員密碼'; return; }\n      if (BUILTIN_HASHES.indexOf(hash) !== -1) { if (adminMsg) adminMsg.textContent = '此密碼已是內建密碼'; return; }\n      var extras = getExtraHashes();\n      if (extras.indexOf(hash) !== -1) { if (adminMsg) adminMsg.textContent = '此密碼已存在'; return; }\n      extras.push(hash);\n      saveExtraHashes(extras);\n      newPwInput.value = '';\n      if (adminMsg) {\n        adminMsg.textContent = '⚠ 已加入本機 localStorage（其他裝置無效，要全體生效需改原始碼重部署）';\n        setTimeout(function () { adminMsg.textContent = ''; }, 5000);\n      }\n      renderHashList();\n    });\n  }\n\n  if (addPwBtn) {\n    addPwBtn.addEventListener('click', addPassword);\n  }\n  if (newPwInput) {\n    newPwInput.addEventListener('keydown', function (e) {\n      if (e.key === 'Enter') addPassword();\n    });\n  }\n\n  if (enterSiteBtn) {\n    enterSiteBtn.addEventListener('click', enterSite);\n  }\n})();\n\n</script>\n</body>\n\n</html>\n","static/js/app.js":"/* =========================================================\n   亮言 · 即時翻譯  —  前端主程式\n   模式：單人 (逐句 STT / Gemini Live 即時) + 面對面 (上下對開翻轉)\n   後端：/api/translate 代理 (Gemini / OpenAI 相容)\n   ========================================================= */\n\n// ---------- 語言清單 ----------\n// name: 給 LLM 的目標語言描述；label: UI 顯示；bcp: STT/TTS 用的 BCP-47\nconst LANGS = [\n    { id: 'zh-TW', name: 'Traditional Chinese (Taiwan)', label: 'CHT-台灣繁體', bcp: 'zh-TW' },\n    { id: 'zh-HK', name: 'Traditional Chinese (Hong Kong)', label: 'CHT-香港繁中', bcp: 'zh-HK' },\n    { id: 'zh-CN', name: 'Simplified Chinese', label: 'CHS-簡體中文', bcp: 'zh-CN' },\n    { id: 'ja',    name: 'Japanese', label: 'Japanese-日本語', bcp: 'ja-JP' },\n    { id: 'en',    name: 'English', label: 'English-美語(美)', bcp: 'en-US' },\n    { id: 'ko',    name: 'Korean', label: 'Korean-한국어', bcp: 'ko-KR' },\n    { id: 'th',    name: 'Thai', label: 'Thai-泰語', bcp: 'th-TH' },\n    { id: 'tr',    name: 'Turkish', label: 'Turkish-土耳其語', bcp: 'tr-TR' },\n    { id: 'my',    name: 'Burmese', label: 'Burmese-緬甸語', bcp: 'my-MM' },\n    { id: 'vi',    name: 'Vietnamese', label: 'Vietnam-越南語', bcp: 'vi-VN' },\n    { id: 'id',    name: 'Indonesian', label: 'Indonesia-印尼語', bcp: 'id-ID' },\n    { id: 'ms',    name: 'Malay', label: 'Malay-馬來語', bcp: 'ms-MY' },\n    { id: 'km',    name: 'Khmer', label: 'Khmer-高棉文', bcp: 'km-KH' },\n    { id: 'fr',    name: 'French', label: 'French-法語', bcp: 'fr-FR' },\n    { id: 'de',    name: 'German', label: 'German-德語', bcp: 'de-DE' },\n    { id: 'es',    name: 'Spanish', label: 'Spanish-西班牙語', bcp: 'es-ES' },\n    { id: 'it',    name: 'Italian', label: 'Italian-義大利語', bcp: 'it-IT' },\n    { id: 'ru',    name: 'Russian', label: 'Russian-俄語', bcp: 'ru-RU' },\n];\nconst byId = id => LANGS.find(l => l.id === id) || LANGS[0];\n\n// ---------- 設定 ----------\nconst DEFAULT_CFG = {\n    provider: 'gemini', baseurl: 'https://api.openai.com/v1', apikey: '', model: '',\n    geminikey: '', tavilykey: '', owmkey: '',          // 集中管理的第三方金鑰（皆選填）\n    rate: 1, autospeak: true,\n    s_langA: 'zh-TW', s_langB: 'en',\n    f_langTop: 'en', f_langBottom: 'zh-TW',\n    cur_from: 'JPY', cur_to: 'TWD', cur_amount: '1',   // 匯率換算：預設日圓→台幣\n    wx_place: '',                                       // 天氣：上次查詢地點\n};\nfunction loadCfg() {\n    try { return { ...DEFAULT_CFG, ...JSON.parse(localStorage.getItem('liang_cfg') || '{}') }; }\n    catch { return { ...DEFAULT_CFG }; }\n}\nfunction saveCfg(c) { localStorage.setItem('liang_cfg', JSON.stringify(c)); }\nlet cfg = loadCfg();\n\n// ---------- DOM ----------\nconst $ = id => document.getElementById(id);\nconst statusDot = $('statusDot');\n\n// ---------- Toast ----------\nlet toastTimer;\nfunction toast(msg, isError = true) {\n    const t = $('toast');\n    t.textContent = msg;\n    t.style.background = isError ? 'var(--danger)' : 'var(--ok)';\n    t.classList.remove('hidden');\n    clearTimeout(toastTimer);\n    toastTimer = setTimeout(() => t.classList.add('hidden'), 3500);\n}\n\n// ---------- 供應商設定（拍照/檔案與文字翻譯共用邏輯）----------\n// Gemini 一律用伺服器內建金鑰；OpenAI 相容才送使用者金鑰/網址\nfunction providerBody() {\n    const isOpenai = cfg.provider === 'openai';\n    let model = cfg.model || '';\n    if (!isOpenai && model && !model.startsWith('gemini')) model = '';   // 避免模型名跨供應商誤送\n    return {\n        provider: cfg.provider,\n        base_url: isOpenai ? cfg.baseurl : '',\n        // OpenAI 用 OpenAI 金鑰；Gemini 用「選填的 Gemini 覆蓋金鑰」（留空後端自動用伺服器內建）\n        api_key: isOpenai ? cfg.apikey : (cfg.geminikey || ''),\n        model,\n    };\n}\n\n// ---------- 翻譯 API ----------\nasync function translate(text, sourceLangId, targetLangId) {\n    const src = byId(sourceLangId), tgt = byId(targetLangId);\n    // 只在 OpenAI 相容時送使用者金鑰/網址；Gemini 一律用伺服器內建金鑰\n    const isOpenai = cfg.provider === 'openai';\n    let model = cfg.model || '';\n    // 避免把 OpenAI 模型名誤送給 Gemini（反之亦然）\n    if (!isOpenai && model && !model.startsWith('gemini')) model = '';\n    const body = {\n        provider: cfg.provider,\n        text,\n        source: src.name,\n        target: tgt.name,\n        base_url: isOpenai ? cfg.baseurl : '',\n        api_key: isOpenai ? cfg.apikey : '',\n        model: model,\n    };\n    const res = await fetch('/api/translate', {\n        method: 'POST',\n        headers: { 'Content-Type': 'application/json' },\n        body: JSON.stringify(body),\n    });\n    const data = await res.json();\n    if (!data.ok) throw new Error(data.error || '翻譯失敗');\n    return data.translation;\n}\n\n// ---------- TTS ----------\nconst synth = window.speechSynthesis;\n// 瀏覽器內建朗讀（依賴手機語音包）；onEnd 於念完或出錯時回呼\nfunction browserSpeak(text, bcp, onEnd = null) {\n    if (!synth || !text) { onEnd?.(); return; }\n    try {\n        synth.cancel();\n        const u = new SpeechSynthesisUtterance(text);\n        u.lang = bcp;\n        u.rate = parseFloat(cfg.rate) || 1;\n        const voices = synth.getVoices();\n        const prefix = bcp.split('-')[0];\n        const v = voices.find(x => x.lang === bcp) || voices.find(x => x.lang.startsWith(prefix));\n        if (v) u.voice = v;\n        u.onend = () => onEnd?.();\n        u.onerror = () => onEnd?.();\n        synth.speak(u);\n    } catch (e) { console.warn('TTS error', e); onEnd?.(); }\n}\n// 主朗讀：優先用雲端 Gemini TTS（任何語言都有聲音，免裝手機語音包），失敗才用瀏覽器\n// force=true 無視自動朗讀設定（手動朗讀鈕）；onEnd 於播放結束回呼（供「停止」鈕重置狀態）\nasync function speak(text, bcp, force = false, onEnd = null) {\n    if ((!cfg.autospeak && !force) || !text) { onEnd?.(); return; }\n    // 先中斷前一句尚在播放或排隊的語音，確保只念最新這一句。\n    // 否則雲端 TTS 會依 nextTime 一段段往後排，把之前累積的語音接連重播，聽起來像重複、延遲。\n    stopAllAudio();\n    try {\n        const res = await fetch('/api/tts', {\n            method: 'POST', headers: { 'Content-Type': 'application/json' },\n            body: JSON.stringify({ text, gemini_key: cfg.geminikey || '' })\n        });\n        if (res.ok) {\n            const buf = await res.arrayBuffer();\n            if (buf && buf.byteLength > 44) { onAllAudioEnd = onEnd; playLiveAudio(buf); return; }\n        }\n    } catch (e) { console.warn('雲端 TTS 失敗，改用瀏覽器', e); }\n    browserSpeak(text, bcp, onEnd);   // 後備\n}\n// 在使用者點擊當下解鎖音訊（手機／iOS 要求音訊須由手勢啟動，否則靜音）\nfunction ensureAudioUnlocked() {\n    try {\n        if (!playCtx) playCtx = new (window.AudioContext || window.webkitAudioContext)({ sampleRate: 24000 });\n        if (playCtx.state === 'suspended') playCtx.resume();\n    } catch (e) { /* ignore */ }\n}\n// 停止所有朗讀（雲端 Web Audio + 瀏覽器 TTS）\nfunction stopAllAudio() {\n    audioSources.forEach(s => { try { s.onended = null; s.stop(); } catch (e) {} });\n    audioSources = [];\n    nextTime = 0;\n    if (synth) { try { synth.cancel(); } catch (e) {} }\n    const cb = onAllAudioEnd; onAllAudioEnd = null; cb?.();\n}\nif (synth) synth.onvoiceschanged = () => synth.getVoices();\n\n// ---------- STT (Web Speech API) ----------\nconst SR = window.SpeechRecognition || window.webkitSpeechRecognition;\nfunction sttSupported() { return !!SR; }\n\n// 手機（Android/Chrome）的國語辨識常回傳簡體字，即使 lang 設 zh-TW 也一樣。\n// 這裡用 OpenCC 把辨識結果轉回繁體；OpenCC 未載入時原字輸出，不影響其他語言。\nlet _s2t = null, _s2tReady = false;\nfunction toTraditional(text) {\n    if (!text) return text;\n    try {\n        if (!_s2tReady) { _s2tReady = true; if (window.OpenCC) _s2t = window.OpenCC.Converter({ from: 'cn', to: 'tw' }); }\n        return _s2t ? _s2t(text) : text;\n    } catch (e) { return text; }\n}\n// 只有辨識語言為繁體中文時才需要轉換\nfunction convForBcp(bcp, text) {\n    return (bcp === 'zh-TW' || bcp === 'zh-HK') ? toTraditional(text) : text;\n}\n\nclass Recognizer {\n    constructor({ bcp, onInterim, onDone, onState }) {\n        this.bcp = bcp; this.onInterim = onInterim; this.onDone = onDone; this.onState = onState;\n        this.active = false; this.rec = null; this.buffer = '';\n    }\n    start() {\n        if (!SR) { toast('此瀏覽器不支援語音辨識，請改用文字輸入'); return; }\n        if (this.active) { this.stop(); return; }   // 再點一下 = 停止並翻譯\n        this.buffer = '';                            // 開始新的一段，清空累積\n        const rec = new SR();\n        rec.lang = this.bcp;\n        rec.interimResults = true;\n        rec.continuous = true;\n        rec.onresult = (e) => {\n            let interim = '';\n            for (let i = e.resultIndex; i < e.results.length; i++) {\n                const r = e.results[i];\n                // 已確定的句段累積起來，但先不翻譯；只有停止時才整段送出\n                // 繁中辨識先轉回繁體，避免手機回傳簡體字\n                if (r.isFinal) this.buffer += convForBcp(this.bcp, r[0].transcript);\n                else interim += convForBcp(this.bcp, r[0].transcript);\n            }\n            // 即時顯示逐字稿（已確定 + 正在辨識），讓使用者看到自己講到哪\n            const shown = (this.buffer + interim).trim();\n            if (shown) this.onInterim?.(shown);\n        };\n        rec.onerror = (e) => {\n            if (e.error === 'no-speech' || e.error === 'aborted') return;\n            if (e.error === 'not-allowed') toast('麥克風權限被拒絕，請允許後重試');\n            else toast('語音辨識錯誤：' + e.error);\n        };\n        rec.onend = () => {\n            if (this.active) { try { rec.start(); } catch {} }  // 自動續聽\n            else this.onState?.(false);\n        };\n        this.rec = rec;\n        this.active = true;\n        try { rec.start(); this.onState?.(true); } catch (e) { toast('無法啟動麥克風'); this.active = false; }\n    }\n    stop() {\n        this.active = false;\n        if (this.rec) { try { this.rec.stop(); } catch {} }\n        this.onState?.(false);\n        const text = this.buffer.trim();   // 講完了，整段一次交出去翻譯\n        this.buffer = '';\n        if (text) this.onDone?.(text);\n    }\n}\n\n// ---------- 歷史 ----------\nfunction pushHistory(src, dst) {\n    const h = JSON.parse(localStorage.getItem('liang_hist') || '[]');\n    h.unshift({ src, dst, t: Date.now() });\n    localStorage.setItem('liang_hist', JSON.stringify(h.slice(0, 100)));\n}\nfunction renderHistory() {\n    const list = $('historyList');\n    const h = JSON.parse(localStorage.getItem('liang_hist') || '[]');\n    if (!h.length) { list.innerHTML = '<div class=\"history-empty\">尚無紀錄</div>'; return; }\n    list.innerHTML = h.map(x =>\n        `<div class=\"history-item\"><div class=\"src\">${escapeHtml(x.src)}</div><div class=\"dst\">${escapeHtml(x.dst)}</div></div>`\n    ).join('');\n}\nfunction escapeHtml(s) { return (s || '').replace(/[&<>]/g, c => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;' }[c])); }\n\n// ---------- 填充語言下拉 ----------\nfunction fillSelect(sel, selectedId) {\n    sel.innerHTML = LANGS.map(l => `<option value=\"${l.id}\">${l.label}</option>`).join('');\n    sel.value = selectedId;\n}\nfunction initSelects() {\n    fillSelect($('s_langA'), cfg.s_langA);\n    fillSelect($('s_langB'), cfg.s_langB);\n    fillSelect($('f_langTop'), cfg.f_langTop);\n    fillSelect($('f_langBottom'), cfg.f_langBottom);\n}\n\n/* =========================================================\n   單人模式\n   ========================================================= */\nconst sResult = $('s_result');\nfunction setResult(box, text, interim = false) {\n    box.classList.add('active');\n    box.innerHTML = interim\n        ? `<span class=\"interim\">${escapeHtml(text)}</span>`\n        : escapeHtml(text);\n}\n\n// 文字翻譯\n$('s_text').addEventListener('input', (e) => { $('s_count').textContent = `${e.target.value.length}/200`; });\n$('s_send').addEventListener('click', async () => {\n    const text = $('s_text').value.trim();\n    if (!text) return;\n    const a = $('s_langA').value, b = $('s_langB').value;\n    try {\n        setResult(sResult, '翻譯中…', true);\n        const out = await translate(text, a, b);\n        setResult(sResult, out);\n        speak(out, byId(b).bcp);\n        pushHistory(text, out);\n    } catch (e) { toast(e.message); setResult(sResult, '（翻譯失敗）'); }\n});\n\n// 對調語言\n$('s_swap').addEventListener('click', () => {\n    const a = $('s_langA').value; $('s_langA').value = $('s_langB').value; $('s_langB').value = a;\n    cfg.s_langA = $('s_langA').value; cfg.s_langB = $('s_langB').value; saveCfg(cfg);\n});\n$('s_langA').addEventListener('change', () => { cfg.s_langA = $('s_langA').value; saveCfg(cfg); });\n$('s_langB').addEventListener('change', () => { cfg.s_langB = $('s_langB').value; saveCfg(cfg); });\n\n// 單人麥克風：依引擎切換\nfunction currentEngine() { return document.querySelector('input[name=engine]:checked').value; }\n\nconst sRecognizer = new Recognizer({\n    bcp: byId(cfg.s_langA).bcp,\n    onInterim: (t) => setResult(sResult, t, true),\n    onDone: async (t) => {\n        // 使用者按停後才會進來：麥克風已停，整段一次翻譯（朗讀也不會被辨識佔用）\n        const a = $('s_langA').value, b = $('s_langB').value;\n        try {\n            setResult(sResult, '翻譯中…', true);\n            const out = await translate(t, a, b);\n            setResult(sResult, out);\n            speak(out, byId(b).bcp);\n            pushHistory(t, out);\n        } catch (e) { toast(e.message); setResult(sResult, '（翻譯失敗）'); }\n    },\n    onState: (on) => toggleMic($('s_mic'), on),\n});\n\nfunction toggleMic(btn, on) {\n    btn.classList.toggle('listening', on);\n    const lbl = btn.querySelector('.mic-label');\n    if (lbl) lbl.textContent = on ? '🎙️ 說話中…說完再點一下翻譯' : '點一下開始說話';\n}\n\n$('s_mic').addEventListener('click', () => {\n    if (currentEngine() === 'live') { toggleLive(); return; }\n    sRecognizer.bcp = byId($('s_langA').value).bcp;\n    sRecognizer.start();\n});\n\n/* =========================================================\n   Gemini Live 即時模式 (socket 串流)\n   ========================================================= */\n// socket.io 由 CDN 載入；若載入失敗，仍要保證「文字/逐句」功能可用\nlet socket = null;\ntry {\n    if (typeof io === 'function') {\n        socket = io({ transports: ['websocket', 'polling'] });\n        socket.on('connect', () => statusDot.classList.add('connected'));\n        socket.on('disconnect', () => { statusDot.classList.remove('connected'); if (liveOn) stopLive(); });\n        socket.on('error', (d) => toast('伺服器：' + (d.msg || 'error')));\n    } else {\n        console.warn('socket.io 未載入，Gemini Live 即時模式停用');\n    }\n} catch (e) { console.warn('socket.io init 失敗', e); }\n\nlet liveOn = false, audioCtx, liveProcessor, liveInput, liveStream;\nlet livePending = '';\nif (socket) {\n    socket.on('text_response', (d) => { if (d.text) { livePending += d.text; setResult(sResult, livePending); } });\n    socket.on('turn_complete', () => {\n        // 即時模式由 Gemini 直接吐語音（audio_response 播放），不需再用瀏覽器 TTS，避免雙重朗讀\n        if (livePending.trim()) pushHistory('(即時語音)', livePending.trim());\n        livePending = '';\n    });\n    socket.on('audio_response', (data) => { playLiveAudio(data); });\n}\n\n// 播放 Gemini Live 原生語音 (24kHz PCM 16-bit)\nlet playCtx = null, nextTime = 0;\nlet audioSources = [];      // 進行中的 Web Audio 節點（供停止用）\nlet onAllAudioEnd = null;   // 全部播放結束時的回呼（供「停止」鈕重置狀態）\nfunction playLiveAudio(data) {\n    try {\n        if (!playCtx) playCtx = new (window.AudioContext || window.webkitAudioContext)({ sampleRate: 24000 });\n        if (playCtx.state === 'suspended') playCtx.resume();   // 手機須解鎖後才有聲音\n        const int16 = new Int16Array(data);\n        const f32 = new Float32Array(int16.length);\n        for (let i = 0; i < int16.length; i++) f32[i] = int16[i] / 32768;\n        const buf = playCtx.createBuffer(1, f32.length, 24000);\n        buf.getChannelData(0).set(f32);\n        const src = playCtx.createBufferSource();\n        src.buffer = buf; src.connect(playCtx.destination);\n        const now = playCtx.currentTime;\n        if (nextTime < now) nextTime = now;\n        src.start(nextTime); nextTime += buf.duration;\n        audioSources.push(src);\n        src.onended = () => {\n            audioSources = audioSources.filter(s => s !== src);\n            if (audioSources.length === 0) { const cb = onAllAudioEnd; onAllAudioEnd = null; cb?.(); }\n        };\n    } catch (e) { console.warn('play audio error', e); }\n}\n\nasync function toggleLive() { liveOn ? stopLive() : startLive(); }\n\nasync function startLive() {\n    if (!socket) { toast('即時模式需要伺服器連線 (socket.io 未載入)'); return; }\n    try {\n        liveStream = await navigator.mediaDevices.getUserMedia({ audio: true });\n        audioCtx = audioCtx || new (window.AudioContext || window.webkitAudioContext)();\n        liveInput = audioCtx.createMediaStreamSource(liveStream);\n        liveProcessor = audioCtx.createScriptProcessor(4096, 1, 1);\n        liveInput.connect(liveProcessor);\n        liveProcessor.connect(audioCtx.destination);\n        const targetRate = 16000;\n        liveProcessor.onaudioprocess = (e) => {\n            if (!liveOn) return;\n            const input = e.inputBuffer.getChannelData(0);\n            const rate = audioCtx.sampleRate;\n            const step = rate / targetRate;\n            const len = Math.floor(input.length / step);\n            const pcm = new Int16Array(len);\n            for (let i = 0; i < len; i++) {\n                let s = Math.max(-1, Math.min(1, input[Math.floor(i * step)] || 0));\n                pcm[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;\n            }\n            socket.emit('audio_in', pcm.buffer);\n        };\n        socket.emit('start_session', {\n            langA: byId($('s_langA').value).name, langB: byId($('s_langB').value).name,\n            gemini_key: cfg.geminikey || '',\n        });\n        liveOn = true; toggleMic($('s_mic'), true);\n        setResult(sResult, '即時聆聽中…', true);\n    } catch (e) { toast('無法啟動麥克風：' + e.name); }\n}\nfunction stopLive() {\n    liveOn = false; toggleMic($('s_mic'), false);\n    if (liveProcessor) { liveProcessor.disconnect(); liveProcessor = null; }\n    if (liveInput) { liveInput.disconnect(); liveInput = null; }\n    if (liveStream) { liveStream.getTracks().forEach(t => t.stop()); liveStream = null; }\n    if (socket) socket.emit('stop_session');\n}\n\n/* =========================================================\n   面對面模式\n   ========================================================= */\nfunction makeFaceSide(langSelId, resultBoxId, micBtnId, getTargetId) {\n    const box = $(resultBoxId), btn = $(micBtnId);\n    const rec = new Recognizer({\n        bcp: byId($(langSelId).value).bcp,\n        onInterim: (t) => setResult(box, t, true),\n        onDone: async (t) => {\n            // 講完按停才會進來：麥克風已停，整段一次翻譯\n            const src = $(langSelId).value, tgt = getTargetId();\n            try {\n                const out = await translate(t, src, tgt);\n                // 顯示在「對面那一側」的框\n                const otherBox = (resultBoxId === 'f_resultBottom') ? $('f_resultTop') : $('f_resultBottom');\n                setResult(otherBox, out);\n                speak(out, byId(tgt).bcp);\n                pushHistory(t, out);\n            } catch (e) { toast(e.message); }\n        },\n        onState: (on) => btn.classList.toggle('listening', on),\n    });\n    btn.addEventListener('click', () => { rec.bcp = byId($(langSelId).value).bcp; rec.start(); });\n    return rec;\n}\n// 下方(你)講 bottom 語言 → 翻成 top 語言，顯示在 top(翻轉給對面看)\nmakeFaceSide('f_langBottom', 'f_resultBottom', 'f_micBottom', () => $('f_langTop').value);\n// 上方(對面)講 top 語言 → 翻成 bottom 語言，顯示在 bottom\nmakeFaceSide('f_langTop', 'f_resultTop', 'f_micTop', () => $('f_langBottom').value);\n$('f_langTop').addEventListener('change', () => { cfg.f_langTop = $('f_langTop').value; saveCfg(cfg); });\n$('f_langBottom').addEventListener('change', () => { cfg.f_langBottom = $('f_langBottom').value; saveCfg(cfg); });\n\n/* =========================================================\n   模式切換\n   ========================================================= */\nlet mode = 'single';\n$('modeBtn').addEventListener('click', () => {\n    if (liveOn) stopLive();\n    mode = mode === 'single' ? 'face' : 'single';\n    $('singleView').classList.toggle('hidden', mode !== 'single');\n    $('faceView').classList.toggle('hidden', mode !== 'face');\n    $('modeBtn').textContent = mode === 'single' ? '👤 單人' : '👥 面對面';\n});\n\n/* =========================================================\n   設定 Modal\n   ========================================================= */\nfunction openSettings() {\n    $('cfg_provider').value = cfg.provider;\n    $('cfg_baseurl').value = cfg.baseurl;\n    $('cfg_apikey').value = cfg.apikey;\n    $('cfg_model').value = cfg.model;\n    $('cfg_geminikey').value = cfg.geminikey || '';\n    $('cfg_tavilykey').value = cfg.tavilykey || '';\n    $('cfg_owmkey').value = cfg.owmkey || '';\n    $('cfg_rate').value = cfg.rate;\n    $('cfg_autospeak').checked = cfg.autospeak;\n    toggleOpenaiFields();\n    $('settingsModal').classList.remove('hidden');\n}\nfunction toggleOpenaiFields() {\n    $('openaiFields').style.display = $('cfg_provider').value === 'openai' ? 'block' : 'none';\n}\n$('cfg_provider').addEventListener('change', toggleOpenaiFields);\n$('settingsBtn').addEventListener('click', openSettings);\n$('cfg_cancel').addEventListener('click', () => $('settingsModal').classList.add('hidden'));\n$('cfg_save').addEventListener('click', () => {\n    cfg.provider = $('cfg_provider').value;\n    cfg.baseurl = $('cfg_baseurl').value.trim();\n    cfg.apikey = $('cfg_apikey').value.trim();\n    cfg.model = $('cfg_model').value.trim();\n    cfg.geminikey = $('cfg_geminikey').value.trim();\n    cfg.tavilykey = $('cfg_tavilykey').value.trim();\n    cfg.owmkey = $('cfg_owmkey').value.trim();\n    cfg.rate = $('cfg_rate').value;\n    cfg.autospeak = $('cfg_autospeak').checked;\n    saveCfg(cfg);\n    $('settingsModal').classList.add('hidden');\n    toast('已儲存設定', false);\n});\n\n/* =========================================================\n   歷史 Modal\n   ========================================================= */\n$('historyBtn').addEventListener('click', () => { renderHistory(); $('historyModal').classList.remove('hidden'); });\n$('hist_close').addEventListener('click', () => $('historyModal').classList.add('hidden'));\n$('hist_clear').addEventListener('click', () => { localStorage.removeItem('liang_hist'); renderHistory(); });\n\n/* =========================================================\n   拍照翻譯 / 上傳檔案翻譯 (摘要 + 翻譯)\n   後端一律走 Gemini 雲端多模態，忽略 OpenAI 設定\n   ========================================================= */\nconst visionModal = $('visionModal');\nlet lastVisionText = '';   // 供「朗讀」按鈕使用\n\n// 相機影像 client 端縮圖：省流量、加速雲端辨識（Gemini 最佳邊長約 1568px）\nfunction fileToDownscaledDataURL(file, maxDim = 1568, quality = 0.85) {\n    return new Promise((resolve, reject) => {\n        const img = new Image();\n        const url = URL.createObjectURL(file);\n        img.onload = () => {\n            URL.revokeObjectURL(url);\n            const scale = Math.min(1, maxDim / Math.max(img.width, img.height));\n            const w = Math.round(img.width * scale), h = Math.round(img.height * scale);\n            const canvas = document.createElement('canvas');\n            canvas.width = w; canvas.height = h;\n            canvas.getContext('2d').drawImage(img, 0, 0, w, h);\n            resolve(canvas.toDataURL('image/jpeg', quality));\n        };\n        img.onerror = () => { URL.revokeObjectURL(url); reject(new Error('圖片讀取失敗')); };\n        img.src = url;\n    });\n}\nfunction dataURLToBlob(dataURL) {\n    const [head, b64] = dataURL.split(',');\n    const mime = (head.match(/data:(.*?);/) || [, 'image/jpeg'])[1];\n    const bin = atob(b64);\n    const arr = new Uint8Array(bin.length);\n    for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);\n    return new Blob([arr], { type: mime });\n}\n\nfunction openVision(title) {\n    stopAllAudio(); setVisionSpeakBtn(false);   // 開新的一張前，先停掉上一段朗讀\n    $('visionTitle').textContent = title;\n    $('visionResult').classList.add('hidden');\n    $('visionSummary').textContent = '';\n    $('visionTranslation').textContent = '';\n    $('visionStatus').textContent = '';\n    const prev = $('visionPreview'); prev.classList.add('hidden'); prev.innerHTML = '';\n    lastVisionText = '';\n    visionModal.classList.remove('hidden');\n}\nfunction renderVision(result) {\n    $('visionStatus').textContent = result.note ? ('ℹ️ ' + result.note) : '';\n    const summary = (result.summary || '').trim();\n    const translation = (result.translation || '').trim();\n    $('visionSummary').textContent = summary || '（無摘要）';\n    $('visionTranslation').textContent = translation || '（無可翻譯文字）';\n    $('visionResult').classList.remove('hidden');\n    lastVisionText = translation || summary;\n    if (translation || summary) {\n        pushHistory('（拍照／檔案）', (summary ? summary + '\\n' : '') + translation);\n    }\n}\n\n// --- 相機拍照 ---\n$('s_camera').addEventListener('click', () => $('cameraInput').click());\n$('cameraInput').addEventListener('change', async (e) => {\n    const file = e.target.files && e.target.files[0];\n    e.target.value = '';                         // 允許再次拍同一來源\n    if (!file) return;\n    openVision('📷 拍照翻譯');\n    try {\n        $('visionStatus').textContent = '影像處理中…';\n        const dataURL = await fileToDownscaledDataURL(file);\n        $('visionPreview').innerHTML = `<img src=\"${dataURL}\" alt=\"preview\">`;\n        $('visionPreview').classList.remove('hidden');\n        $('visionStatus').textContent = '雲端辨識與翻譯中…（約數秒）';\n        const target = byId($('vision_target').value).name;\n        const res = await fetch('/api/vision', {\n            method: 'POST', headers: { 'Content-Type': 'application/json' },\n            body: JSON.stringify({ image: dataURL, target, ...providerBody() }),\n        });\n        const data = await res.json();\n        if (!data.ok) throw new Error(data.error || '辨識失敗');\n        renderVision(data);\n    } catch (err) { $('visionStatus').textContent = '❌ ' + err.message; toast(err.message); }\n});\n\n// --- 上傳檔案（圖片 / PDF / 文字檔）---\n$('s_file').addEventListener('click', () => $('fileInput').click());\n$('fileInput').addEventListener('change', async (e) => {\n    const file = e.target.files && e.target.files[0];\n    e.target.value = '';\n    if (!file) return;\n    openVision('📎 檔案翻譯');\n    try {\n        const fd = new FormData();\n        fd.append('target', byId($('vision_target').value).name);\n        const pb = providerBody();\n        Object.keys(pb).forEach(k => fd.append(k, pb[k]));\n        if (file.type.startsWith('image/')) {\n            // 圖片先縮圖再上傳，並顯示預覽\n            const dataURL = await fileToDownscaledDataURL(file);\n            $('visionPreview').innerHTML = `<img src=\"${dataURL}\" alt=\"preview\">`;\n            $('visionPreview').classList.remove('hidden');\n            fd.append('file', dataURLToBlob(dataURL), 'upload.jpg');\n        } else {\n            $('visionPreview').innerHTML = `<div class=\"file-chip\">📄 ${escapeHtml(file.name)}</div>`;\n            $('visionPreview').classList.remove('hidden');\n            fd.append('file', file);\n        }\n        $('visionStatus').textContent = '上傳與翻譯中…（檔案越大越久）';\n        const res = await fetch('/api/file', { method: 'POST', body: fd });\n        const data = await res.json();\n        if (!data.ok) throw new Error(data.error || '翻譯失敗');\n        renderVision(data);\n    } catch (err) { $('visionStatus').textContent = '❌ ' + err.message; toast(err.message); }\n});\n\n// 朗讀鈕：可切換 —— 沒在念就開始念，念的過程中變「⏹ 停止」，可隨時中斷\nlet visionSpeaking = false;\nfunction setVisionSpeakBtn(on) {\n    visionSpeaking = on;\n    $('vision_speak').textContent = on ? '⏹ 停止' : '🔊 朗讀';\n}\n$('vision_speak').addEventListener('click', () => {\n    if (visionSpeaking) { stopAllAudio(); return; }   // 念到一半按 = 停止\n    if (!lastVisionText) { toast('沒有可朗讀的內容'); return; }\n    ensureAudioUnlocked();                              // 手機須在點擊當下解鎖音訊\n    setVisionSpeakBtn(true);\n    // 手動朗讀，不受自動朗讀設定影響；播放結束（自然念完或被停止）時把鈕還原\n    speak(lastVisionText, byId($('vision_target').value).bcp, true, () => setVisionSpeakBtn(false));\n});\n$('vision_close').addEventListener('click', () => {\n    stopAllAudio();                                    // 關閉同時停掉雲端與瀏覽器語音\n    setVisionSpeakBtn(false);\n    visionModal.classList.add('hidden');\n});\n\n/* =========================================================\n   匯率換算（免金鑰：後端代理 ER-API / Frankfurter）\n   ========================================================= */\nconst CURRENCIES = [\n    { code: 'TWD', label: 'TWD 台幣' },\n    { code: 'USD', label: 'USD 美元' },\n    { code: 'JPY', label: 'JPY 日圓' },\n    { code: 'KRW', label: 'KRW 韓元' },\n    { code: 'CNY', label: 'CNY 人民幣' },\n    { code: 'HKD', label: 'HKD 港幣' },\n    { code: 'EUR', label: 'EUR 歐元' },\n    { code: 'GBP', label: 'GBP 英鎊' },\n    { code: 'THB', label: 'THB 泰銖' },\n    { code: 'SGD', label: 'SGD 新加坡幣' },\n    { code: 'MYR', label: 'MYR 馬來幣' },\n    { code: 'VND', label: 'VND 越南盾' },\n    { code: 'IDR', label: 'IDR 印尼盾' },\n    { code: 'PHP', label: 'PHP 披索' },\n    { code: 'AUD', label: 'AUD 澳幣' },\n    { code: 'CAD', label: 'CAD 加幣' },\n];\nfunction fillCur(sel, code) {\n    sel.innerHTML = CURRENCIES.map(c => `<option value=\"${c.code}\">${c.label}</option>`).join('');\n    sel.value = code;\n}\nfunction fmtMoney(n) {\n    if (!isFinite(n)) return '—';\n    const dp = Math.abs(n) >= 100 ? 2 : 4;   // 大額 2 位、小額 4 位\n    return n.toLocaleString('en-US', { minimumFractionDigits: 0, maximumFractionDigits: dp });\n}\nfunction persistCur() {\n    cfg.cur_from = $('cur_from').value;\n    cfg.cur_to = $('cur_to').value;\n    cfg.cur_amount = $('cur_amount').value;\n    saveCfg(cfg);\n}\nlet curTimer = null;\nasync function doConvert() {\n    const amount = parseFloat($('cur_amount').value);\n    const from = $('cur_from').value, to = $('cur_to').value;\n    if (!isFinite(amount)) { $('cur_result').textContent = '請輸入金額'; $('cur_rate').textContent = ''; return; }\n    $('cur_result').textContent = '換算中…';\n    try {\n        const res = await fetch('/api/currency', {\n            method: 'POST', headers: { 'Content-Type': 'application/json' },\n            body: JSON.stringify({ base: from, target: to, amount }),\n        });\n        const d = await res.json();\n        if (!d.ok) throw new Error(d.error || '查詢失敗');\n        $('cur_result').textContent = `${fmtMoney(amount)} ${from} = ${fmtMoney(d.result)} ${to}`;\n        const when = (d.date || '').replace(' (UTC)', '').slice(0, 16);\n        $('cur_rate').textContent = `1 ${from} ≈ ${fmtMoney(d.rate)} ${to}` + (when ? `　·　${when}` : '');\n    } catch (e) { $('cur_result').textContent = '—'; toast(e.message); }\n}\nfunction scheduleConvert() { clearTimeout(curTimer); curTimer = setTimeout(doConvert, 350); }\n\n$('s_currency').addEventListener('click', () => {\n    fillCur($('cur_from'), cfg.cur_from);\n    fillCur($('cur_to'), cfg.cur_to);\n    $('cur_amount').value = cfg.cur_amount || '1';\n    $('currencyModal').classList.remove('hidden');\n    doConvert();\n});\n$('cur_swap').addEventListener('click', () => {\n    const a = $('cur_from').value; $('cur_from').value = $('cur_to').value; $('cur_to').value = a;\n    persistCur(); doConvert();\n});\n$('cur_from').addEventListener('change', () => { persistCur(); doConvert(); });\n$('cur_to').addEventListener('change', () => { persistCur(); doConvert(); });\n$('cur_amount').addEventListener('input', () => { persistCur(); scheduleConvert(); });\n$('cur_convert').addEventListener('click', doConvert);\n$('cur_close').addEventListener('click', () => $('currencyModal').classList.add('hidden'));\n\n/* =========================================================\n   天氣（Open-Meteo，免金鑰；填了 OWM 金鑰後端可改用 OpenWeatherMap）\n   ========================================================= */\nasync function fetchWeather(payload) {\n    $('wx_result').classList.add('hidden');\n    $('wx_status').textContent = '查詢中…';\n    try {\n        const res = await fetch('/api/weather', {\n            method: 'POST', headers: { 'Content-Type': 'application/json' },\n            body: JSON.stringify({ ...payload, owm_key: cfg.owmkey || '' }),\n        });\n        const d = await res.json();\n        if (!d.ok) throw new Error(d.error || '查詢失敗');\n        const rows = [\n            `<div class=\"wx-place\">${escapeHtml(d.place)}</div>`,\n            `<div class=\"wx-temp\">${Math.round(d.temp)}°C　${escapeHtml(d.desc)}</div>`,\n            `<div class=\"wx-sub\">體感 ${Math.round(d.feels)}°C · 濕度 ${d.humidity}%` +\n                (d.hi != null ? ` · 高${Math.round(d.hi)}° 低${Math.round(d.lo)}°` : '') +\n                (d.pop != null ? ` · 降雨 ${d.pop}%` : '') + `</div>`,\n            `<div class=\"wx-advice\">${escapeHtml(d.advice)}</div>`,\n        ];\n        $('wx_result').innerHTML = rows.join('');\n        $('wx_result').classList.remove('hidden');\n        $('wx_status').textContent = '';\n    } catch (e) { $('wx_status').textContent = '❌ ' + e.message; }\n}\n$('s_weather').addEventListener('click', () => {\n    $('wx_place').value = cfg.wx_place || '';\n    $('wx_result').classList.add('hidden');\n    $('wx_status').textContent = '';\n    $('weatherModal').classList.remove('hidden');\n    if (cfg.wx_place) fetchWeather({ place: cfg.wx_place });\n});\n$('wx_go').addEventListener('click', () => {\n    const p = $('wx_place').value.trim();\n    if (!p) { $('wx_status').textContent = '請輸入地點'; return; }\n    cfg.wx_place = p; saveCfg(cfg);\n    fetchWeather({ place: p });\n});\n$('wx_place').addEventListener('keydown', (e) => { if (e.key === 'Enter') $('wx_go').click(); });\n$('wx_geo').addEventListener('click', () => {\n    if (!navigator.geolocation) { $('wx_status').textContent = '此裝置不支援定位'; return; }\n    $('wx_status').textContent = '定位中…';\n    navigator.geolocation.getCurrentPosition(\n        (pos) => fetchWeather({ lat: pos.coords.latitude, lon: pos.coords.longitude }),\n        () => { $('wx_status').textContent = '無法取得位置（請允許定位權限）'; }\n    );\n});\n$('wx_close').addEventListener('click', () => $('weatherModal').classList.add('hidden'));\n\n/* =========================================================\n   旅遊助手問答（可選 Tavily 上網 + 設定的供應商）\n   ========================================================= */\nlet lastAskText = '';\nlet askSpeaking = false;\nfunction setAskSpeakBtn(on) { askSpeaking = on; $('ask_speak').textContent = on ? '⏹ 停止' : '🔊 朗讀'; }\nasync function doAsk() {\n    const q = $('ask_q').value.trim();\n    if (!q) { $('ask_status').textContent = '請輸入問題'; return; }\n    $('ask_answer').classList.add('hidden');\n    $('ask_sources').innerHTML = '';\n    $('ask_status').textContent = (cfg.tavilykey ? '上網查詢並' : 'AI ') + '思考中…';\n    try {\n        const res = await fetch('/api/ask', {\n            method: 'POST', headers: { 'Content-Type': 'application/json' },\n            body: JSON.stringify({\n                question: q,\n                target: byId(cfg.s_langA).name,      // 用你的語言回答\n                tavily_key: cfg.tavilykey || '',\n                ...providerBody(),\n            }),\n        });\n        const d = await res.json();\n        if (!d.ok) throw new Error(d.error || '查詢失敗');\n        $('ask_status').textContent = d.searched ? '🌐 已參考即時搜尋' : '';\n        $('ask_answer').textContent = d.answer || '（無回覆）';\n        $('ask_answer').classList.remove('hidden');\n        lastAskText = d.answer || '';\n        if (Array.isArray(d.sources) && d.sources.length) {\n            $('ask_sources').innerHTML = '<div class=\"src-title\">來源</div>' + d.sources.map(s =>\n                `<a href=\"${s.url}\" target=\"_blank\" rel=\"noopener\">${escapeHtml(s.title || s.url)}</a>`\n            ).join('');\n        }\n        if (q && lastAskText) pushHistory('（助手）' + q, lastAskText);\n    } catch (e) { $('ask_status').textContent = '❌ ' + e.message; toast(e.message); }\n}\n$('s_ask').addEventListener('click', () => {\n    setAskSpeakBtn(false);\n    $('askModal').classList.remove('hidden');\n});\n$('ask_go').addEventListener('click', doAsk);\n$('ask_speak').addEventListener('click', () => {\n    if (askSpeaking) { stopAllAudio(); return; }\n    if (!lastAskText) { toast('沒有可朗讀的內容'); return; }\n    ensureAudioUnlocked();\n    setAskSpeakBtn(true);\n    speak(lastAskText, byId(cfg.s_langA).bcp, true, () => setAskSpeakBtn(false));\n});\n$('ask_close').addEventListener('click', () => { stopAllAudio(); setAskSpeakBtn(false); $('askModal').classList.add('hidden'); });\n\n/* =========================================================\n   啟動\n   ========================================================= */\nfillSelect($('vision_target'), cfg.s_langA);   // 拍照/檔案：預設翻成你的語言\ninitSelects();\nif (!sttSupported()) {\n    console.warn('本瀏覽器不支援 Web Speech API，語音辨識不可用（可改用文字或 Gemini Live）');\n}\n// 註冊 Service Worker (PWA)\nif ('serviceWorker' in navigator) {\n    navigator.serviceWorker.register('/sw.js').catch(e => console.warn('SW 註冊失敗', e));\n}\n","static/css/style.css":":root {\n    --bg1: #1a1030;\n    --bg2: #2a1a4a;\n    --bg3: #3a2560;\n    --gold: #f5c451;\n    --gold-soft: #f7d98a;\n    --text: #f3eefb;\n    --muted: #b9a9d6;\n    --card: rgba(255, 255, 255, 0.07);\n    --card-border: rgba(245, 196, 81, 0.25);\n    --danger: #ff6b6b;\n    --ok: #5bd18a;\n}\n\n* { box-sizing: border-box; margin: 0; padding: 0; -webkit-tap-highlight-color: transparent; }\n\nhtml, body {\n    height: 100%;\n    font-family: 'Noto Sans TC', system-ui, sans-serif;\n    color: var(--text);\n    background: linear-gradient(160deg, var(--bg1), var(--bg2) 55%, var(--bg3));\n    overflow: hidden;\n}\n\n.app {\n    height: 100dvh;\n    display: flex;\n    flex-direction: column;\n    max-width: 640px;\n    margin: 0 auto;\n}\n\n/* ---------- 頂部列 ---------- */\n.topbar {\n    display: flex;\n    align-items: center;\n    justify-content: space-between;\n    padding: 14px 16px;\n    border-bottom: 1px solid rgba(255,255,255,0.08);\n}\n.brand { display: flex; align-items: center; gap: 10px; }\n.brand h1 { font-size: 1.05rem; font-weight: 900; letter-spacing: .5px; }\n.brand h1::first-letter { color: var(--gold); }\n.dot { width: 10px; height: 10px; border-radius: 50%; background: var(--danger); box-shadow: 0 0 8px var(--danger); transition: .3s; }\n.dot.connected { background: var(--ok); box-shadow: 0 0 8px var(--ok); }\n.top-actions { display: flex; gap: 8px; }\n.icon-btn {\n    background: var(--card); border: 1px solid var(--card-border); color: var(--text);\n    border-radius: 12px; padding: 7px 11px; font-size: .82rem; font-weight: 700; cursor: pointer;\n    font-family: inherit; transition: .2s;\n}\n.icon-btn:active { transform: scale(.94); }\n\n/* ---------- 通用 view ---------- */\n.view { flex: 1; display: flex; flex-direction: column; padding: 16px; gap: 14px; overflow: hidden; }\n.hidden { display: none !important; }\n\n/* ---------- 語言列 ---------- */\n.lang-bar { display: flex; align-items: center; gap: 10px; }\n.lang-select {\n    flex: 1; background: var(--card); border: 1px solid var(--card-border); color: var(--text);\n    border-radius: 14px; padding: 12px; font-size: 1rem; font-family: inherit; font-weight: 700;\n    text-align: center; appearance: none;\n}\n.lang-select option { background: var(--bg2); color: var(--text); }\n.swap-btn {\n    background: var(--gold); color: #2a1a4a; border: none; border-radius: 50%;\n    width: 42px; height: 42px; font-size: 1.2rem; font-weight: 900; cursor: pointer; flex-shrink: 0;\n    transition: .2s;\n}\n.swap-btn:active { transform: rotate(180deg) scale(.9); }\n\n/* ---------- 結果框 ---------- */\n.result-box {\n    flex: 1; background: var(--card); border: 1px solid rgba(255,255,255,0.1);\n    border-radius: 18px; padding: 20px; font-size: 1.5rem; font-weight: 500; line-height: 1.5;\n    /* 靠上、靠左排列（不垂直置中）：長文從第一行開始，捲動也看得到最上面 */\n    display: block; text-align: left;\n    overflow-y: auto; transition: .3s; min-height: 90px;\n}\n.result-box.active { border-color: var(--gold); box-shadow: 0 0 20px rgba(245,196,81,.2); }\n.result-box .placeholder { color: var(--muted); font-size: 1rem; font-weight: 400; }\n.result-box .interim { color: var(--muted); font-style: italic; }\n\n/* ---------- 視覺化 ---------- */\n.visualizer { display: flex; align-items: center; justify-content: center; gap: 4px; height: 26px; }\n.visualizer span { width: 4px; height: 6px; background: var(--gold); border-radius: 2px; transition: height .1s; opacity: .5; }\n.visualizer.active span { opacity: 1; }\n\n/* ---------- 引擎選擇 ---------- */\n.engine-row { display: flex; gap: 8px; flex-wrap: wrap; }\n.engine-pill {\n    flex: 1; min-width: 140px; background: var(--card); border: 1px solid var(--card-border);\n    border-radius: 12px; padding: 8px 10px; font-size: .72rem; color: var(--muted); cursor: pointer;\n    display: flex; align-items: center; gap: 6px;\n}\n.engine-pill input { accent-color: var(--gold); }\n\n/* ---------- 麥克風 ---------- */\n.mic-btn {\n    background: linear-gradient(135deg, var(--gold), var(--gold-soft));\n    color: #2a1a4a; border: none; border-radius: 18px; padding: 16px;\n    font-size: 1.05rem; font-weight: 900; font-family: inherit; cursor: pointer;\n    display: flex; align-items: center; justify-content: center; gap: 10px; transition: .2s;\n}\n.mic-btn .mic-ico { font-size: 1.3rem; }\n.mic-btn:active { transform: scale(.97); }\n.mic-btn.listening {\n    background: linear-gradient(135deg, #ff8a5b, #ff6b6b); color: #fff;\n    animation: pulse 1.2s infinite;\n}\n@keyframes pulse { 0%,100% { box-shadow: 0 0 0 0 rgba(255,107,107,.5);} 50% { box-shadow: 0 0 0 12px rgba(255,107,107,0);} }\n\n/* ---------- 文字輸入 ---------- */\n.text-row { background: var(--card); border: 1px solid var(--card-border); border-radius: 16px; padding: 10px; }\n.text-row textarea {\n    width: 100%; background: transparent; border: none; color: var(--text); resize: none;\n    font-family: inherit; font-size: 1rem; min-height: 44px; outline: none;\n}\n.text-meta { display: flex; align-items: center; justify-content: space-between; margin-top: 6px; }\n.text-meta span { color: var(--muted); font-size: .8rem; }\n.send-btn {\n    background: var(--gold); color: #2a1a4a; border: none; border-radius: 10px;\n    padding: 7px 16px; font-weight: 900; font-family: inherit; cursor: pointer;\n}\n\n/* ---------- 拍照 / 上傳工具列 ---------- */\n.tool-row { display: flex; gap: 10px; }\n.tool-btn {\n    flex: 1; background: var(--card); border: 1px solid var(--card-border); color: var(--text);\n    border-radius: 14px; padding: 12px; font-size: .95rem; font-weight: 700; font-family: inherit;\n    cursor: pointer; transition: .2s;\n}\n.tool-btn:active { transform: scale(.96); }\n\n/* ---------- 拍照 / 檔案結果 ---------- */\n.vision-preview { margin: 10px 0; text-align: center; }\n.vision-preview img { max-width: 100%; max-height: 220px; border-radius: 12px; border: 1px solid var(--card-border); }\n.vision-preview .file-chip {\n    display: inline-block; padding: 10px 16px; border-radius: 12px;\n    background: rgba(0,0,0,.25); border: 1px solid var(--card-border); color: var(--text); font-size: .9rem;\n}\n.vision-status { min-height: 18px; margin: 6px 0; }\n.vision-section { margin-top: 14px; }\n.vision-section h3 { margin: 0 0 6px; font-size: .95rem; color: var(--gold-soft); }\n.vision-text {\n    background: rgba(0,0,0,.22); border: 1px solid var(--card-border); border-radius: 12px;\n    padding: 12px 14px; font-size: 1.02rem; line-height: 1.6; white-space: pre-wrap; word-break: break-word;\n}\n\n/* ---------- 匯率換算 ---------- */\n.cur-row { display: flex; align-items: center; gap: 10px; margin: 12px 0; }\n.cur-result {\n    text-align: center; font-size: 1.5rem; font-weight: 900; color: var(--gold);\n    background: rgba(0,0,0,.22); border: 1px solid var(--card-border); border-radius: 14px;\n    padding: 18px 14px; margin-top: 6px; word-break: break-word;\n}\n.cur-rate { text-align: center; margin-top: 8px; }\n\n/* ---------- 天氣 ---------- */\n.wx-search { display: flex; gap: 8px; margin: 6px 0; }\n.wx-search input {\n    flex: 1; background: rgba(0,0,0,.25); border: 1px solid var(--card-border);\n    color: var(--text); border-radius: 10px; padding: 10px; font-family: inherit; font-size: .95rem;\n}\n.wx-search button { flex-shrink: 0; border-radius: 10px; padding: 10px 16px; }\n.wx-geo { width: 100%; margin: 4px 0 8px; padding: 10px; border-radius: 10px;\n    background: transparent; border: 1px solid var(--card-border); color: var(--text);\n    font-family: inherit; font-weight: 700; cursor: pointer; }\n.wx-result {\n    background: rgba(0,0,0,.22); border: 1px solid var(--card-border); border-radius: 14px;\n    padding: 18px; text-align: center; margin-top: 6px;\n}\n.wx-place { color: var(--muted); font-size: .95rem; }\n.wx-temp { font-size: 2rem; font-weight: 900; color: var(--gold); margin: 6px 0; }\n.wx-sub { font-size: .9rem; color: var(--text); }\n.wx-advice { margin-top: 10px; font-size: 1rem; font-weight: 700; }\n\n/* ---------- 旅遊助手 ---------- */\n#ask_q {\n    width: 100%; background: rgba(0,0,0,.25); border: 1px solid var(--card-border);\n    color: var(--text); border-radius: 12px; padding: 12px; font-family: inherit; font-size: 1rem;\n    resize: vertical; outline: none;\n}\n.ask-sources { margin-top: 10px; display: flex; flex-direction: column; gap: 6px; }\n.ask-sources .src-title { color: var(--muted); font-size: .78rem; margin-bottom: 2px; }\n.ask-sources a { color: var(--gold-soft); font-size: .85rem; text-decoration: none; word-break: break-all; }\n.ask-sources a:hover { text-decoration: underline; }\n\n/* ---------- 面對面模式 ---------- */\n#faceView { padding: 0; }\n.face-panel { flex: 1; display: flex; padding: 16px; overflow: hidden; }\n.face-panel.top { transform: rotate(180deg); background: rgba(245,196,81,0.04); }\n.face-inner { flex: 1; display: flex; flex-direction: column; gap: 12px; }\n.face-result { font-size: 1.4rem; }\n.face-mic { padding: 13px; font-size: .95rem; }\n.face-divider {\n    display: flex; align-items: center; justify-content: center; position: relative;\n    padding: 6px 0; background: rgba(0,0,0,.2);\n}\n.face-divider span { color: var(--muted); font-size: .72rem; letter-spacing: 1px; }\n.face-divider::before, .face-divider::after {\n    content: ''; position: absolute; top: 50%; width: 30%; height: 1px; background: var(--card-border);\n}\n.face-divider::before { left: 5%; } .face-divider::after { right: 5%; }\n\n/* ---------- Modal ---------- */\n.modal {\n    position: fixed; inset: 0; background: rgba(0,0,0,.6); backdrop-filter: blur(4px);\n    display: flex; align-items: center; justify-content: center; z-index: 50; padding: 16px;\n}\n.modal-card {\n    background: linear-gradient(160deg, var(--bg2), var(--bg3)); border: 1px solid var(--card-border);\n    border-radius: 20px; padding: 22px; width: 100%; max-width: 440px; max-height: 88dvh; overflow-y: auto;\n}\n.modal-card h2 { color: var(--gold); font-size: 1.2rem; margin-bottom: 14px; }\n.modal-card h3 { font-size: .95rem; margin: 18px 0 6px; color: var(--gold-soft); }\n.modal-card .hint { color: var(--muted); font-size: .78rem; margin-bottom: 10px; line-height: 1.4; }\n.modal-card label { display: block; font-size: .82rem; color: var(--muted); margin: 10px 0; }\n.modal-card label.check { display: flex; align-items: center; gap: 8px; }\n.modal-card input[type=text], .modal-card input[type=password], .modal-card select {\n    width: 100%; margin-top: 5px; background: rgba(0,0,0,.25); border: 1px solid var(--card-border);\n    color: var(--text); border-radius: 10px; padding: 10px; font-family: inherit; font-size: .95rem;\n}\n.modal-card input[type=range] { width: 100%; accent-color: var(--gold); }\n.modal-actions { display: flex; gap: 10px; margin-top: 20px; }\n.modal-actions button { flex: 1; padding: 12px; border-radius: 12px; font-weight: 900; font-family: inherit; cursor: pointer; border: none; }\n.modal-actions .ghost { background: transparent; border: 1px solid var(--card-border); color: var(--text); }\n.modal-actions .primary { background: var(--gold); color: #2a1a4a; }\n\n/* ---------- 歷史 ---------- */\n.history-list { max-height: 55dvh; overflow-y: auto; }\n.history-item { background: var(--card); border-radius: 12px; padding: 12px; margin-bottom: 8px; }\n.history-item .src { color: var(--muted); font-size: .82rem; }\n.history-item .dst { color: var(--text); font-size: 1rem; font-weight: 700; margin-top: 4px; }\n.history-empty { color: var(--muted); text-align: center; padding: 30px; }\n\n/* ---------- Toast ---------- */\n.toast {\n    position: fixed; bottom: 24px; left: 50%; transform: translateX(-50%);\n    background: var(--danger); color: #fff; padding: 12px 20px; border-radius: 12px;\n    font-size: .88rem; font-weight: 700; z-index: 99; max-width: 90%; text-align: center;\n    box-shadow: 0 6px 20px rgba(0,0,0,.4);\n}\n","static/sw.js":"/* 亮言 · 即時翻譯 — Service Worker (PWA)\n   網路優先 (network-first)：線上一律拿最新版，離線才用快取，避免更新被舊快取卡住。 */\nconst CACHE = 'liang-translate-v10';\n\nself.addEventListener('install', (e) => {\n    self.skipWaiting();  // 新版立即接手\n});\n\nself.addEventListener('activate', (e) => {\n    e.waitUntil(\n        caches.keys().then(keys => Promise.all(keys.map(k => caches.delete(k))))  // 清掉所有舊快取\n    );\n    self.clients.claim();\n});\n\nself.addEventListener('fetch', (e) => {\n    const url = new URL(e.request.url);\n    if (url.pathname.startsWith('/api/') || url.pathname.startsWith('/socket.io/')) return;\n    if (e.request.method !== 'GET') return;\n    // 網路優先：先抓最新，順便更新快取；沒網路才用快取\n    e.respondWith(\n        fetch(e.request).then(res => {\n            const copy = res.clone();\n            caches.open(CACHE).then(c => c.put(e.request, copy)).catch(() => {});\n            return res;\n        }).catch(() => caches.match(e.request).then(hit => hit || caches.match('/')))\n    );\n});\n","static/manifest.json":"{\n  \"name\": \"亮言 · 即時翻譯\",\n  \"short_name\": \"亮言翻譯\",\n  \"description\": \"雙向即時語音翻譯 — 單人與面對面模式，支援 Gemini 與 OpenAI 相容供應商\",\n  \"start_url\": \"/\",\n  \"display\": \"standalone\",\n  \"orientation\": \"portrait\",\n  \"background_color\": \"#1a1030\",\n  \"theme_color\": \"#2a1a4a\",\n  \"icons\": [\n    { \"src\": \"/static/icon-192.png\", \"sizes\": \"192x192\", \"type\": \"image/png\", \"purpose\": \"any maskable\" },\n    { \"src\": \"/static/icon-512.png\", \"sizes\": \"512x512\", \"type\": \"image/png\", \"purpose\": \"any maskable\" }\n  ]\n}\n"};
